INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289216','На Різдво','Музика: Віра Боднарук Слова: Руслана Боднарук. Виконує: Віра Боднарук','uk','ukraine_before_1917',NULL,NULL,'http://beta.navsi100.com/vira-bodnaruk/music#9617',NULL,'Зірка ясна запалала на весь світ,
Щоб утішився увесь наш славний рід.
На Різдво кружляє білий сніг
І несе нам добру звістку на поріг.

Приспів:
Хай Різдво принесе у вашу хату щастя,
Хай добро і здоров''я буде з вами завжди!
За столом нехай збирається родина,
Прославляємо Божого Сина.
Буде мир, буде радість, буде все, що треба.
Запалає зоря і звеселиться небо.
Силу дасть тобі Йорданськая вода,
На свята нехай лунає коляда!

Білі янголи кружляють в небесах.
Срібні дзвоники у їхніх голосах.
Запали свічу і помолись,
До традицій наших давніх доторкнись.

Приспів.','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289216'), datetime('now')),datetime('now'));
