INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289199','Небесну Сотню, Господи, прийми','Музика: Павло Табаков. Виконує: Павло Табаков','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Понад Майданом стелиться туман...
Звільнімось, рідні, кров''ю від кайдан.
Хай бачить весь великий Божий світ
Вкраїни нашої незламний цвіт.

Тривожне небо сипле білий сніг,
Пора іти за батьківський поріг,
Над Україною запалені вогні,
Повстаньте, браття, у своїй землі!
Не плачте, мамо, досить у житті
Народу сльози проливать в журбі.
Я йду туди, де в нашу волю й честь
Стріляють із злочинних перехресть.

Приспів:
Небесну Сотню, Господи, прийми,    |
Прийми їх душі з білими крильми,   |
Прости, Всевишній, що не вберегли, |
Свого народу кращії сини.          | (2)

Кривавий сніг та здимлене лице,
Холодний щит життя не вбереже,
Та крок за кроком зранений іду,
Хай я помру та вже не відступлю.

Приспів.

Небесну Сотню, Господи, прийми...
Небесну Сотню, Господи, прийми...','["pisni.org.ua", "cat:devoted", "cat:euromaydan", "Пісні присвячені окремим особам", "Пісні Євромайдану"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289199'), datetime('now')),datetime('now'));
