INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289369','Дід Мороз','Слова: Володимир Мацуцький','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Йшов ти, Діду, довго,
Всі стоптав доріжки.
То ж сідай із нами
Та спочинеш трішки.

Ми тобі, Дідусю,
Будемо співати
Про ялинку нашу,
Про веселе свято!

Ми весело всі грались,
Співали й танцювали.
Дід Мороз, і ти давай -
Затанцюй і поспівай!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289369'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2289369','Дід Мороз','Йшов ти, Діду, довго,
