INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289420','Чарівний світ Різдва','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Різдво засяяло
Чарівним вогником
І тихо спустилася з небес,
Постукала до нас
Добра казка -
Ми їй відчинили
Серця для чудес!

Приспів:
Різдво, Різдво, Різдво,
Як чудово,
Що ти до нас прийшло!
Від свічок ми збережемо тепло
І в долоні
Один одному дамо!

Зірки в небі кружляють
У срібному танці
І все осявають колом.
Ми таке чудове свято
Зустрічаємо,
Йому цю ніжну пісню співаємо!

Приспів. (2)','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289420'), datetime('now')),datetime('now'));
