INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289277','Миколай','Музика: Ірина Батюк Слова: Віталій Войтко. Виконує: Богдан Бира','uk','ukraine_1991',NULL,NULL,'Аудіофайл',NULL,'Снігом вкрилось все довкола,
Став казковим гай,
Йде з небес до нас у гості
Святий Миколай.
А з ним божі янголята
В кожний дім спішать,
Щоб для діточок слухняних
Іграшки роздать.

Приспів:
Миколая на землі
Ждуть дорослі і малі,
Він щорік спішить до нас
В святковий час.
Миколай у кожний дім
Принесе гостинці всім.
Він щорік спішить
В такий святковий час.

Подарунків в Миколая
Завжди повний міх,
І він щедро обдарує
Діточок усіх.
Під подушку справжню мрію
Тихо покладе,
Бо добро у кожнім серці
Вміло віднайде.

Приспів. (2)','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289277'), datetime('now')),datetime('now'));
