INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2290798','Укроп','Музика: Гайдамаки Слова: Олександр Ткачук. Виконує: Гайдамаки','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Укроп - це маленький хлопчик,
Що носить коротенький чубчик
І мріє про мир у домі
А як треба то стане в окоп в обороні.
Укроп - це школярка юна
Окутана стягом жовтоблакитиним
Горять у неї очі,
Як плете маскувальну сітку до ночі.

Приспів:
Укроп - це ти, укроп - це я,
Україна - укропів земля,
Укроп всіяний по полю,
Бореться за свободу і волю!

Укроп - це лагідна мати,
Що молиться до світання
Укроп - це батько суворий,
Що є патріотом рідного краю!
Укроп - це бабуся старенька,
Що в''яже панчохи захиснику,
Укроп - це дідо сивенький,
Збирає вояці сальця й часнику.

Приспів. (2)

Укроп - це кіборг залізний,
Укроп - це козак вольовий,
Тікай, враже-сєпар, допоки не пізно,
Ховайся, москалю, допоки живий!
Укроп голови не схилить
І навіть вистоїть смерч,
Укроп градом накриє,
А він всеодно підійме свій меч!

Приспів. (2)

Укроп - то народ єдиний, |
Укроп - то народ міцний, |
Укроп ніколи не згине,   |
Укроп вічно живий!       | (2)

Приспів. (2)','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2290798'), datetime('now')),datetime('now'));
