INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229010','Горі малинячком','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Самвидавний туристський пісенник: Там на Лемковині помедже горами. - Літо 1981. 2. http://www.lemko.org/lemko/ns/wesila/wesila.html','Вказаний у джерелі 1 пісенник створений українцем з Польщі Лехом Ляхом. Ймовірно, що обробка тексту й мелодії, підбір акордів здійснені ним. У цьому збірнику пісня називається "Горе малинячком". Пісню співають під час лемківського весілля. Дивіться джерело 2. Діалектизми: бы-м - би я; вера - правда, справді; главичка - голова; горі, гори - догори; долу - додолу; єй - її; же - що, (а також: же, ж); жебы - щоб, щоби; жениченька - жіночка, дружина; лем - тільки, але; любував - кохав, любив; малинячок - малинник; мі - мені; мыслила-с - ти думала; ня - мене; палюнка - горілка; хыжа - хата; юж - вже; юж-єм - вже я.','Em
Горі* малинячком,
Долу малинячком,
Назвало ня дівча, гей,   |
Em             |(2)**
Великим пиячком.         |

Я не п''ю палюнкы***,
Лем палену воду,
Не кохам дівчатко, гей,
А лем єй уроду.

Палюночку пив бы-м,
Дівчатко любив бы-м,
Чорны очка мала, гей,
Вера, полюбив бы-м!

Дай же мі, Боженьку,
Гарду жениченьку,
Жебы ня водила, гей,
З корчмы за рученьку.

Жебы ня водила,
Жебы ня не била;
Добра бы то, Боже, гей,
Жениченька была!

Мыслила-с, мамичко,
Же ся ня не збудеш,
Я ти повідала, гей,
Же плакати будеш!

Ой плачу я, плачу
На свою мамичку,
Же ня замуж дала, гей,
Таку невеличку...

Ни мі з хлопом спати,
Ни в хыжы лишати;
Ой, Боже мій, Боже, гей,
Што ж буде почати?

Юж-єм ся оженив,
Юж навікы амінь,
Юж-єм си прив''язав, гей,
До главичкы камінь.

Юж-єм ся оженив,
Юж буду свою мав,
А юж вас, дівчата, гей,
Не буду любував!

Весіля ся кінчыт,
Біда ся зачынат,
Пані млада плаче, гей,
Же юж не вытрымат...

Ни шыти, ни прясти,
Ни хыжу підмести,
Корови не здоїт,
Бо ся хвоста боїт.****
*У різних джерелах трапляється "горе", "гори" та "горі".

**Всі в''язки (куплети) виконуйте за взірцем першої.

***У джерелі 1 надруковано "палінкы".

****У джерелі 1 ця в''язка відсутня.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229010'), datetime('now')),datetime('now'));
