INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2292111','Заспіваймо пісню за Україну','Музика: Олександр Пономарьов Слова: Олександр Пономарьов. Виконує: Олександр Пономарьов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми ніколи не зречемося
Рідної мови!
Ми ніколи не зречемося
Рідної землі!
І борітеся - поборите
Будь-які змови!
І борітеся -
Поборите все, що у злі!

Приспів:
Заспіваймо пісню за Україну!
За її незалежність, за волю її!
Заспіваймо пісню за Україну,
Бо потрібна допомога
Моїй рідній землі!

Ми піднімемо наш прапор
Знову і знову!
Слава рідній Україні,
Слава рідній землі!
І борітеся - поборите
Будь-які змови!
І борітеся -
Поборите все, що у злі!

Приспів. (2)','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2292111'), datetime('now')),datetime('now'));
