INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229022','Новацький марш','(Ясне сонце). Музика: Юрій Пясецький Слова: Юрій Пясецький','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ясне сонце в небі сяє
І зелений бір шумить.
Гей, готуйсь, новаче жвавий,
Гей, готуйсь, біда не спить!

Вірний Богу й Україні,
Пластовий шануй Закон.
Гей, готуйся вже віднині
На завзятий бій зі злом!

Там, у лісі змій крилатий
Схопив бранку молоду.
Гей, готуйся визволяти
Україну з полону!','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229022'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229022','Новацький марш','Ясне сонце в небі сяє
І зелений бір шумить.
Гей, готуйсь, новаче жвавий,
Гей, готуйсь, біда не спить!

Вірний Богу й Україні,
Пластовий шануй Закон.
Гей, готуйся вже віднині
На завзятий бій зі злом!

Там, у лісі змій крилатий
Схопив бранку молоду.
Гей, готуйся визволяти
Україну з полону!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289293','Новий рік! Хай луна веселий сміх!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ти зустрів знову свято,
Де пісень так багато
І ялинка-свіча
Новий рік зустріча!
Щастя вам, сніжні квіти.
І Різдва зорі світять,
Срібний сміх на вустах,
Свято мрій, білий птах.

Приспів.

Новий рік! Новий рік!
Хай луна веселий сміх!
І єдна в святкове коло
І дорослих, і малих!
Новий рік! Новий рік
Принесе нам на поріг
Сподівання, побажання
Для усіх!

У стрічках серпантину
Хай співа Україна,
Вічний час, вічний лед,
Танець снів і планет.
Ми щасливі сьогодні,
Заметілі холодній,
Де блакитна Земля
В вишині кружля!

Приспів. (2)','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289293'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2289293','Новий рік! Хай луна веселий сміх!','Ти зустрів знову свято,
