INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2291012_l1','pisniua_2291012','YouTube','https://www.youtube.com/watch?v=Qg4hxjhlQgU','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2291767','Подруга моя','Музика: Володимир Будейчук Слова: Ірина Зінковська. Виконує: Ірина Зінковська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Розкажи, чому очі знов сумні?
Як сестра, була ти завжди мені.
Розкажи, чому ти, мов тінь, одна,
Де тепер світло з твого вікна?
Відчуваю навіть без слів -
Він тобі ще не відболів...
Поверни любов, не втрачай,
Він прийде, тільки чекай!

Приспів:
Ти його ще вчора любила,
Втратила, знайшла, відпустила.
Ділимо біль ми на двох, ти і я,
Подруго вірна і мила.
Ти його ще вчора любила,
З іншою сьогодні зустріла.
В щасті й біді ми разом, ти і я,
Подруго ти моя.

Не тримай, скажи йому, в чому річ,
Почуття мільйонами протиріч.
В душах двох не стихне розлук надрив,
Лиш тебе єдину він так любив.
Відчуваю навіть без слів -
Він тобі ще не відболів...
Поверни любов, не втрачай,
Він прийде, тільки чекай!

Приспів. (2)','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2291767'), datetime('now')),datetime('now'));
