INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2289414','Сніжинки','Слова: А. Онуків','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Сніжинки спускаються з неба
Усе нижче та нижче...
Замети пухнастого снігу
Все вищі, все вищі...
Кроки, що минають
Все тихіше та тихіше...
А пісенька Нового року
Все ближче, все ближче...

Злетять листки календаря,
Залишиться - листок...
В останній вечір грудня
Прийде чарівний термін...
Проб''є годинник дванадцять разів,
І Дід Мороз прийде
І поведе з собою нас
В щасливий Новий рік!

Приспів.

Нас зустріне казка в цю годину
Під ялинкою лісовою,
І не покине більше нас
Ні літом, ні весною...
І чекає нас диво попереду
І жартома, і всерйоз...
Скоріше приходь в гості
До нас, Дідусь Мороз!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2289414'), datetime('now')),datetime('now'));
