INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229158','Чи Дома Дома Господаренько','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Рай розвився Господь звеселився. Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Чи Думу дума Пан Господар! Листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. Бог, Різдво Світа, Дідух і Лицарі. Українські релігійні роздуми про Бога: Яблучко. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до інших листків про Українські традиції.','Чи Дома-дома Господаренько
Приспів: Ой дай Боже!

Ой знаємо ж ми що є Він Дома
Ой сидить собі по Конець Стола
А коло Нього Служеньки Його
Держать Шапочки поза Вершечки
Пущай нас Пане в Чистеє Поле
В Чистеє Поле Неміряноє
Та най ми Його поміряємо
Вірненьким Плужком тай пооремо
Тай посіємо Яру Пшеницю
Яру Пшеницю всяку Пашницю!','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229158'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229158','Чи Дома Дома Господаренько','Чи Дома-дома Господаренько
