INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_22920','Зашуміли верби при потоці','Музика: Роман Купчинський Слова: Роман Купчинський','uk','ukr_ssr_1919_1991',NULL,'1947','Полум''я (часопис тернопільських пластунів). Співаник.','Пластова мандрівна пісня, створена 1947 року.','Зашуміли верби при потоці,
Гей, гей, долинами.
Збирайтеся ви, хлопці-молодці
Гей, гей, з пластунами.

Збирайтеся ви, хлопці-молодці
Гей, гей, тай у гори.
Несіть ваші ковані топорці
Гей, гей, межи орли.

Та щоб наша рідная держава,
Гей, гей, гомоніла.
Та щоб наша пластовая слава
Гей, гей, не змарніла.','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_22920'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_22920','Зашуміли верби при потоці','Зашуміли верби при потоці,
