INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229192','Чи то буря, чи то грім *','Музика: невідомий Слова: Осип Маковей. Виконує: Буття','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'диск Пісні помаранчевого повстання "Дух не вмирає, дух не згаса..."',NULL,'Чи то буря, чи то грім,
Чи реве хмаролім,
Що земля на сто миль грає грізно,
То зібрався в похід                 |
Український нарід,                  |(2)
В ряд вставай, щоб не було запізно. |

В ряд вставай, готовись,
Ні на що не дивись,
Чи до пекла підеш, чи до неба,
Кидай неньку стару,                 |
Кидай любку і сестру,               |(2)
Бо настала велика потреба.          |

Бо настав такий час,
Що помре кожен з нас
Не на печі, а в полі у бої,
І в годину страшну                  |
Помянеш Вітчизну,                   |(2)
Щоб за неї поляг ти з любови.       |

Наше тіло — то гній,
Для квіток ясних мрій,
Наша кров — то росиця над ранок.
Наша думка то грім,                 |
А душа - хмаролім,                  |
На ворога підем гураганом.          |(2)

Хай усім нам лягти
Не дійти до мети,
Та про нас говоритимуть внуки...
Так боролись колись,                |
Полягли й не здались,               |
А кайдани пірвали на штуки.         |(2)

Чи то буря, чи то грім,
Чи реве хмаролім,
Чи земля на сто миль грає грізно.
Від Кубані аж до гір                |
Чути голос з позір                  |
В ряд вставай, щоб не було запізно. |(2)','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229192'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229192','Чи то буря, чи то грім *','Чи то буря, чи то грім,
