INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2292','Пісня про рушник','(Рідна мати моя). Музика: Платон Майборода Слова: Андрій Малишко. Виконує: Дмитро Гнатюк, Олександр Таранець, Чарівна, Ірина Сказіна, Олександр Малінін, Квітка Цісик, Рушничок, Кобза, Рената Бабак, Сергій Захаров','uk','ukr_ssr_1919_1991',NULL,'1958','1. Українські народні романси. - К.: В-во АН УРСР, 1961. - С. 380. 2. Українські ліричні пісні. - К.: Кн. ф-ка "Жовтень", 1960. - 204 с. 3. Рідна мати моя. Вінок пісень та віршів. Збірник. - К.: Дніпро, 1966. - 328 с. Упорядкування, підготовка текстів та вступна стаття Володимира Бойка.','Пісня з кінофільму "Літа молодії" (1958) режисера Олексія Мішуріна за сценарієм Анатолія Шайкевича. Текст звірений за джерелом [2]. Перша назва пісні "Рідна мати моя" (див. [1, 2]), згодом вона стала знаною під назвою "Пісня про рушник": ця назва трапляється вже у збірнику [3], який названо першими словами пісні. 1959 є роком публікації пісні: прем''єра кінофільму "Літа молодії" відбулася 9 березня 1959 р., друком вона вийшла того ж року (ймовірно це посилання в [1, с. 401], можливі газетні чи журнальні публікації). Написана ж пісня була раніше, принаймні 1958 р. Синтез - гурт "ЧАРIВНА" виконали пiсню з захопленням i любов''ю на чотири голоси з викристанням акустичних iнструментiв - скрипки, бандури, гiтари, бубна. Обробка мелодії Тетяни Маслак. У виконанні гурту рушничок: http://chomikuj.pl/WDR/Muzyka+Ukrai*c5*84ska/Narodowa+-+Folk+-+Regionalna/Rushnychok','Рідна мати моя, ти ночей не доспала
І водила мене у поля край села,
І в дорогу далеку ти мене на зорі проводжала,
І рушник вишиваний на щастя дала,
І в дорогу далеку ти мене на зорі проводжала,
І рушник вишиваний на щастя, на долю дала.
Хай на ньому цвіте росяниста доріжка,
І зелені луги, й солов''їні гаї,
І твоя незрадлива материнська ласкава усмішка,
І засмучені очі хороші твої.
І твоя незрадлива материнська ласкава усмішка,
І засмучені очі хороші блакитні твої.
Я візьму той рушник, простелю, наче долю,
В тихім шелесті трав, в щебетанні дібров.
І на тім рушничкові оживе все знайоме до болю -
І дитинство, й розлука, і вірна любов.
І на тім рушничкові оживе все знайоме до болю -
І дитинство, й розлука, й твоя материнська любов.','["pisni.org.ua", "cat:films", "cat:pro-batkiv", "Українські пісні в кінофільмах", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2292'), datetime('now')),datetime('now'));
