INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2292420','Співаймо, друзі!','Музика: Дмитро Мулик Слова: Роман Завадович','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Під зорями весна ще буде спати,
Ще місто мла вкриватиме густа,
А ми до церкви підем привітати, -
Воскреслого Христа!

Приспів:
Співаймо, друзі, в великоднім колі,
І Господа воскреслого молім...
Щоб обновив весною щастя й долі
Наш рідний край, наш рідний дім.

А в церкві так велично, світло буде,
Заграють дзвони із церковних веж.
І разом з ними заспівають люди:
Христос! Христос Воскрес!

Приспів.

І зійде сонце, наче кругла паска,
Мов писанка, розквітне вся земля -
Радіймо, друзі, великодня казка -
Хай серце звеселя!

Приспів.','["pisni.org.ua", "cat:voskresni", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2292420'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2292420','Співаймо, друзі!','Під зорями весна ще буде спати,
Ще місто мла вкриватиме густа,
