Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229328','Нема в світі Правди Правди не зіскати','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Отець-Рідна-Мати — У Піснях символ Господа Бога і звертання до Нього. Також символ Сім''ї як Святости та присутности Бога (Давня Правдонька Старих Людей). Можлива гра слів: Отець-Рідня-Мати. Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Ой уся Правда тепер погасла. Ой в Ліску в Ліску на Жовтім Піску Нема в світі Правди не зіскати. Що вже тепер Правда стала неправдою жити. Що вже кінець Сьвіту дуже приблизився. Тільки в світі Правди як Отець-Рідна-Мати. Нема в світі Правди (1) Нема в світі Правди (2-3) Нема в світі Правди (4) Нема в світі Правди (5) Тай нема в світі Правди Ускочили Три Козаки тай стали питати. Господа Милосердного прохали та благали. Бо вже ж нам сяя Турецькая Каторга надоїла. Ой да у Святую Неділеньку І самого ж мене у Чорнеє Море іспустіть. Голосна та Правдива як Господа слово. Наша Дума — Наша Пісня не вмре не загине. Б''ють пороги Місяць сходить як і перше сходив У Чистому Степу собі Живности доставати. Байді Молодому Мед-горілку пити. Многая Літа да посієм Жито. Приїдь Синочок напийсь Води. Ой устань же Козаченьку. Чого Старий не женишся. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції. Звукові джерела: Кружало: Гей, на Чорному морi... Кобзарсько-лiрницька традицiя. Микола Будник. Народна бандура. Стрічка: Співає бандурист Микола Будник (Україна). Думи, історичні пісні, псальми, балади. 1997.','Нема в світі Правди Правди не зіскати
Що вже тепер Правда стала неправдою жити

Що вже тепер Правда стоїть у порога
А вража неправда сидить вконець стола

Що вже тепер Правда сльозами ридає
А вража неправда бенкети справляє

Що вже тепер Правда сидить у темниці
А вража неправда засіла в світлиці

Що вже тепер Правда Правда вже померла
А вража неправда увесь світ зажерла','["pisni.org.ua", "cat:dumy", "cat:suspilno-politychni", "Думи", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229328'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229328','Нема в світі Правди Правди не зіскати','Нема в світі Правди Правди не зіскати
Що вже тепер Правда стала неправдою жити

Що вже тепер Правда стоїть у порога
А вража неправда сидить вконець стола

Що вже тепер Правда сльозами ридає
А вража неправда бенкети справляє

Що вже тепер Правда сидить у темниці
А вража неправда засіла в світлиці

Що вже тепер Правда Правда вже померла
А вража неправда увесь світ зажерла');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229471','Листопад','Музика: Андрій Остапенко Слова: Вадим Крищенко. Виконує: Оксана Білозір, Василь Білоцерківський','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Дощі багряні листопаду,
Полинний присмак на губах,
Я звала радість на пораду,
Але прийшла чомусь журба.
Та дайте я ще раз нап''юся
Із чаші дивної пори,
Вже відлетіли білі гуси,
Забравши літа кольори.

Приспів:
Листопад, листопад -
Давня згадка у слові,
Як прощальна сльоза,
Як відлуння любові.
Листопад, листопад,
Я тобі не дозволю,
Прилетівши у сад,
Замести мою долю...

Сади закутані в багрянці,
Не відгукнеш - не відгукнусь,
У листопадовому танці
Ми загубилися чомусь.
З останніми листками саду
Віддаленіли я і ти,
Дощі багряні листопаду
Вже нас не можуть віднайти.

Приспів','["pisni.org.ua", "cat:lirychni", "Пісні про кохання, ліричні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229471'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229471','Листопад','Дощі багряні листопаду,
Полинний присмак на губах,
Я звала радість на пораду,
Але прийшла чомусь журба.
Та дайте я ще раз нап''юся
Із чаші дивної пори,
Вже відлетіли білі гуси,
Забравши літа кольори.

Приспів:
Листопад, листопад -
Давня згадка у слові,
Як прощальна сльоза,
Як відлуння любові.
Листопад, листопад,
Я тобі не дозволю,
Прилетівши у сад,
Замести мою долю...

Сади закутані в багрянці,
Не відгукнеш - не відгукнусь,
У листопадовому танці
Ми загубилися чомусь.
З останніми листками саду
Віддаленіли я і ти,
Дощі багряні листопаду
Вже нас не можуть віднайти.

Приспів');
