INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2293114','Давайте свято зустрічати','Музика: Юрій Гнатковський, Юлія Лорд Слова: Юрій Гнатковський, Юлія Лорд. Виконує: Юрій Гнатковський, Юлія Лорд','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Давайте всі разом будемо співати
І Новий рік веселими піснями зустрічати!
Зберемося разом ялинку прикрашати,
Хороший настрій нам усім даруватиме вона.

Ялинка височить у цю святкову мить,
З небес зіркових Миколай прилітати поспішить,
Давайте скоріше дарунки готувати,
Бо так приємно в Новий рік під ялинкою щось знайти!

Є м''ячик для Богдана і лялька для Луки,
І великий торт, святковий стіл сподобається всім.
Хай усмішками друзів наповниться весь дім,
Хороводом радісним ми затанцюємо усі.

Давайте всі разом будемо співати
І Новий рік веселими піснями зустрічати,
Зберемося разом ялинку прикрашати,
Хороший настрій нам усім даруватиме вона.

Ялинка височить у цю святкову мить,
З небес зіркових Миколай прилітати поспішить,
Давайте скоріше дарунки готувати,
Бо скоро прийде Новий рік...
Бо скоро новорічне свято...','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2293114'), datetime('now')),datetime('now'));
