INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2293716','Травневий дзвоник','Музика: Анатолій Салогуб Слова: Анатолій Салогуб. Виконує: Ірина Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'День травневий сяє, дзвоник калатає,
На подвір''я школи кличе школярів.
Вже вбрання святкове школа одягає,
Бо сьогодні свято - день випускників.

Приспів:
В школі останній дзвоник вже лунає,
Школа, за все ми дякуєм тобі.
Школа дитинство наше проводжає,
Школа, прийми уклін наш до землі.

Ніби вчора мами в школу проводжали,
Вересневі квіти у руках цвіли.
Перший раз у класі ми за парти сіли,
Вперше нас зустріли наші вчителі.

Приспів','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2293716'), datetime('now')),datetime('now'));
