INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229267','Христос воскрес!','Слова: Леонід Глібов','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Христос воскрес! Радійте, люди,
Біжіть у поле, у садок,
Збирайте гіллячко і квіти,
Кладіть на. Божий хрест вінок.

Нехай бринять і пахнуть квіти,
Нехай почує Божий рай,
Як на землі радіють діти
І звеселяють рідний край.

На вас погляне Божа Мати,
Радіючи з святих небес...
Збирайтесь, діти, нум співати...
Христос воскрес!
Христос воскрес!','["pisni.org.ua", "cat:cerkovni", "cat:christian", "cat:dytyachi", "cat:voskresni", "Церковні пісні", "Пісні на християнську тематику", "Дитячі пісні", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229267'), datetime('now')),datetime('now'));
