INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229410','Когда час приходить треба помірати (Страшний суд)','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Співає зі старосвітською бандурою кобзар Микола Будник: Воскресні та Спасительні пісні © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003',NULL,'...Когда час приходить треба помірати,
Славу і богацтво треба покидати.
Когда тей час наступає - ой то лиха година
Чи ж її нам  люди добрії нам з вами вдасться оминути?

Ангели кажуть возтрублять з високого Неба,
Усіх грішних людей у одну мить розбудять.
Усі люди вставайте годі вже бо спати,
Одвіт Богу дайте Творцю своєму

Горітимуть, гори горітимуть ріки,
Ні скелі, ні високії гори не будуть стояти.
А ти грішний чоловіче що будеш гадати,
Як там на правиці стануть розтягати

А той час не одкупить ні Отець ні Мати,
Краще би не родитися ніж у пеклі смажитись.
А ми всі з вами християни гріхов своїх каймось,
Перед Христом Богом  крижем упадаймо.
Бо він нам дарує глас його послухать,
І в Раю навіки у Раю навіки...','["pisni.org.ua", "cat:cerkovni", "cat:dumy", "Церковні пісні", "Думи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229410'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229410','Когда час приходить треба помірати (Страшний суд)','...Когда час приходить треба помірати,
