INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229457','В цьому Домі як у Раю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Рай розвився Господь звеселився. Сад садили Сад поливали. Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Порівняння: Українці й Уралалтайці. Стежки до листків про Українські традиції.','В цьому Домі як у Раю

Приспів:
Щедрий Вечір Добрий Вечір!

Там Господар як Виноград
Там Господиня як Калина
Його сини як Соколи
Її Дочки  як Панночки

По Саду xодили Сад садили
Сад садили Сад поливали
Вищий Мене кращий Мене','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229457'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_229457','В цьому Домі як у Раю','В цьому Домі як у Раю

