INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2294226','Вчительська доля','Музика: Анатолій Салогуб Слова: Любов Зелена. Виконує: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Приходить осінь щедра, величава,
Спішить до школи дітвора дзвінка.
І вчитель зустрічає їх ласкаво,
Як світоч правди, мудрості, добра.
Ця зустріч завжди бажана, жадана,
І стільки в ній надій і сподівань,
Бо стелиться, неначе вишиванка,
Дорога, що веде в країну знань.

Приспівв:
Вам через терни до зірок летіти,
Вести вперед загони молоді.
То ж дай Вам Бог у щасті довго жити,
Зі святом - дорогі учителі!

Та нелегка в нас праця педагога,
І злети мрій, і біль розчарувань.
Така бажана радість перемоги,
Через шалений тиск випробувань.
Як не помітно посивіли скроні,
І як же швидко діти підросли.
І знову голос твій звучить у школі
В очікуванні кращої весни.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2294226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2294226','Вчительська доля','Приходить осінь щедра, величава,
