Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2295063','Алілуя! Христос воскрес!',NULL,'uk','ukraine_1991',NULL,NULL,'християнський пісенник',NULL,'Христе, Ти Дорога наша!
Збережи і приведи нас
В дім Твого Отця.
Вірим в Твоє милосердя,
В день останній воскресиш
До вічного життя.

Приспів:
Алілуя! Христос воскрес,
Останній ворог - смерть -
Не має влади над життям.
Ісусе, Ти Священик,
Святий Жертовний Агнець,
Ти наша Пасха, Христе!
Алілуя!

Христе, Ти Істина наша,
Світлом Твого Воскресіння
Просвіти серця.
Надія в Тобі безмежна,
В День Пасхальний
Повні щастя небо і земля.

Приспів.

Христе, Ти є Життя наше,
Дав нам участь в таємниці
Свого божества.
Любов''ю Святої Трійці
В безвечірній день
Ввійдемо в радість торжества.

Приспів.','["pisni.org.ua", "cat:cerkovni", "cat:voskresni", "Церковні пісні", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2295063'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2295063','Алілуя! Христос воскрес!','Христе, Ти Дорога наша!
