INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2295369','Многа літа Вам бажаємо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'В нашім серці є мелодія,
В нашім серці є хвала,
В нашім серці є подяка
За дар вашого життя.

Приспів:
Многа літа Вам бажаємо!
Многа літа від душі!
Хай Вам сонце усміхається,
Коли падають дощі!

А якщо гроза настане,
Щоб спинити Вас в путі -
То нехай Христос із Вами
Завжди йтиме у житті!

Приспів.

Хай Ісус Вам помагає
Кожен день і кожен час
І повсюди буде з Вами
Матір Божа й ангел Ваш!

Приспів.

Хай Вам завжди світить сонечко,
Буде спокій у душі,
Зичим Вам всього найкращого
І щасливих днів в житті!

Приспів.','["pisni.org.ua", "cat:christian", "cat:pro-batkiv", "Пісні на християнську тематику", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2295369'), datetime('now')),datetime('now'));
