INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2295797','Українці','Музика: Володимир Будейчук Слова: Ірина Зінковська. Виконує: Ірина Зінковська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'У вишиванці в свята й будні
Моя Вкраїна хай цвіте.
Тут мудрі і веселі люди -
Таких немає більш ніде.
Гуцули, бойки, подоляни
І відчайдушні козаки,
Поважні, ґречні галичани -
Мої ви любі земляки!

Приспів:
Українці, ми - єдина сім''я!
Співуча мова, пшенична земля,
Чиста й ніжна, наче пташка на калині,
Вдячна, що я народилась в Україні!

Волинь, Покуття, Чорне море -
Усі під небом ми одним -
Дунай, Дніпро, бескиди, гори,
Бо Україна - це наш дім.
Дзвенять піснями буковинці -
До Запоріжжя йде луна.
Одна родина - українці,
Це наша рідна сторона.

Приспів','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2295797'), datetime('now')),datetime('now'));
