INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2297818','Проти Івана сонце іграло','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Проти Івана сонце іграло,
Ой, рано, на Івана.

А де ж воно ночувало?
Ой, рано, на Івана.

Ночувало у Івана.
Ой, рано, на Івана.

А що ж воно вечеряло?
Ой, рано, на Івана.

Вечеряло варенички,
Ой, рано, на Івана.

Варенички з цибулею,
Ой, рано, на Івана.

З цибулею, з чорним маком,
Ой, рано, на Івана.

З чорним маком, з пастернаком,
Ой, рано, на Івана.

І з юшкою, з петрушкою,
Ой, рано, на Івана.','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2297818'), datetime('now')),datetime('now'));
