INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2294971','Вівати','(Куди б я не їхала). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Галина Дудар. З глибин джерел народних. Конкурсна робота. Моя батьківщина - Україна. Тернопіль, 2014 р.',NULL,'Куди б я не їхала,
Куди я б не йшла,
Я своїй матері дякувала:
Дякую тобі, моя мамо,
Що будила мене рано,
Більше не будеш, не будеш.

Куди б я не їхала,
Куди б я не йшла,
Я своїм віконцям дякувала:
Дякую вам, віконця,
Що втирала до схід сонця,
Більше не буду, не буду.

Куди б я не їхала,
Куди б я не йшла,
Я своїм порогам дякувала:
Дякую вам, пороги,
Що вбивали босі ноги,
Більше не будуть, не будуть.

Куди б я не їхала,
Куди б я не йшла,
Я своїм воротам дякувала:
Дякую вам, ворота,
Що стояла хлопців рота,
Більше не буде, не буде.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2294971'), datetime('now')),datetime('now'));
