INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229495','А вже років триста як козак в неволі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Українські реліґійні роздуми про Воскресіння, Неволю і Спасіння. Пісні Великодні — Спасительні: світ не по Правді. Пісні-плачі Сокола-Прадіда. Ой Ми зіслані на Признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. Гей вийди Доле із Води визволь мене Серденько із біди. А вже років двісті як козак в неволі А вже років двісті як козак у неволі А вже років триста як козак в неволі Вже більше літ двісті як козак в неволі Уже років з двісті як козак в неволі У Чистому Степу собі Живности доставати. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Рокове Коло. Стежки до листків про Українські традиції. Висловлювання: Світ Правди засвітить. Церков-домовина Розвалиться... і з-під неї Встане Україна. І розвіє тьму Неволі, Світ Правди засвітить, І помоляться на Волі Невольничі діти!.. — Тарас Шевченко (http://poetry.uazone.net/kobzar)','А вже років триста як козак в неволі
Понад Дніпром ходить викликає Долю
Гей вийди Доле із води визволь мене Серденько із біди | (2)

А вона йому відповідає (говориться):

Не вийду козаче не вийду соколе
Бо ти добре знаєш що я у неволі
Гей у неволі у ярмі під турецьким караулом у Москві   | (2)','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_229495'), datetime('now')),datetime('now'));
