INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229616','Пішов Молодець в Темний Лїсочок','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пішов Молодець в Темний Лїсочок — Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Були Світилки Яснії Зірки. Не гинь Миленький дам Ти Радоньку. Воскресіння в Парі. Пішов Молодець в Темний Лїсочок Піду в Садочок нарву Квіточок Займив Молодець Коня до Води Івана Купала тай в Воду упала. Читати листки, де є згадка з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до інших листків про Українські традиції.','Пішов (такий то) в Темний Лїсочок
Приспів: Там сам я! Там сам я Молод

В Темнім Лїсочку в Жовтім Пісочку загину !*

Війшов до Него Батенько Єго
Не гинь Синоньку дам ти Радоньку
Війшла до Него Матїнька Єго
Не гинь Синоньку дам ти Радоньку
Війшов до Него Братенько Єго
Не гинь Братеньку дам ти Радоньку
Війшла до него Сестронька Єго
Не гинь Братеньку дам ти Радоньку

Війшла до него Миленька Єго
Не гинь Миленький дам ти Радоньку
Взєла Миленька Милого свого
