INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2298414_l1','pisniua_2298414','YouTube','https://www.youtube.com/watch?v=XXHSJMpRgwE','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2298512','Ніжно, не ніжно','Музика: Андрій Підлужний Слова: Андрій Підлужний. Виконує: Андрій Кузьменко, Скрябін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Заплакана... Не було більше сил
Повірити у то, що я просив...
Налякана, рахуєш свої дні
В календарі на стіні...
Сховалася у сигаретний дим,
Хотілося летіти разом з ним,
Забути смак солодкої брехні,
Розлитої вином в душі...

Приспів:
Ніжно, не ніжно,  |
Але люби!..       |
Ніжно, не ніжно - |
Перетерпи...      | (2)

Запалена свічка на столі
Розкидає ліниві тіні по мені,
Лікує час, але не повертає дні
В календарі на стіні...

