INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_229798','Ой позволь Пан Хазяїн нам Колядочку сказать','Українська народна пісня. Виконує: Тріо Либідь, Олександр Гаркавий','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Щедрий вечір. Українські народні пісні. Упор. та передм. Н.Д.Якименко. - К.: Музична Україна, 1989. - 192 с.','Колядка стародавня: Українське Різдво Світа. Піди принеси Святе Різдво. А на тім же Cтовпі сидить Птиця-Орел. Сидять Святі з Перами промовляють Cловами. Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Стежки до листків про Українські традиції.','Ой позволь Пан Хазяїн нам Колядочку сказать
Свят-Свят Свят Вечір нам Колядочку сказать
І весь Світ звеселять  Свят Вечір

