INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2296993','Гори наші веселенькі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гори наші веселенькі,
Груні з ємочьками,
Накриєм вас, ридні гори,
Ми співаночьками!

Гори наші веселенькі,
На вас сонце гріє,
Росте трава зелененька
Цвіточьок леліє.

Росте трава зелененька,
В глибокім потоці,
З єгидочьок - малиночьок
Витьискаєм сокьи.

Єгидочькьи - малиночькьи,
Афини чьорньенькі,
Напиймоси цего соку,
Пишні - молоденькі!

Напиймоси цего соку
Єкьий солодьенькьий,
Подивітси на Гуцулів,
Єкі ми файньенькі!

Подивітси на Гуцулів,
На Гуцульску вроду,
Бо Гуцули файні людьи
Мудрого Народу!','["pisni.org.ua", "cat:huculski", "Гуцульські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2296993'), datetime('now')),datetime('now'));
