INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_22993','Засвистали козаченьки','(Засвіт встали козаченьки). Українська народна пісня. Виконує: Соколи, Іван Мацялко, Рушничок','uk','ukraine_before_1917',NULL,NULL,'1. Українські пісні / Уклад. О. В. Зав’язкін.– Донецьк: ТОВ ВКФ "БАО", 2003.– 512 с. 2. webmaster (pisni.org.ua)','Перший (основний) варіант тексту подано за джерелом 1. Акорди записано з пам''яті. Підбір акордів: bohdanko (pisni.org.ua)','Засвистали козаченьки
В похід з полуно_  чі,-
Виплакала Марусенька
Свої ясні очі.

Не плач, не плач, Марусенько,
Не плач не журися
Та за свого миленького
Богу помолися.

Стоїть місяць над горою,
Та сонця немає...
Мати сина в доріженьку
Слізно проводжає:

"Іди, іди, мій синочку,
Та й не забавляйся,
За чотири неділеньки
Додому вертайся!"

"Ой, рад би я, матусенько,
Скоріше вернуться,
Та вже щось мій вороненький
В воротях спіткнувся.

Ой, Бог знає, коли вернусь,
В якую годину;
Прийми ж мою Марусенку
За свою дитину!"

"Ой, рада б я Марусеньку
За рідну прийняти,
Та чи буде ж вона мене,
Сину, шанувати?"

"Ой, не плачте, не журітесь,
В тугу не вдавайтесь:
Заграв кінь мій вороненький -
Назад сподівайтесь!"

Варіант тексту 2:

Засвіт встали козаченьки
В похід з полуночі;
Виплакала Марусенька
Свої карі очі.

Не плач, не плач, Марусенько,
Не плач не журися,
А за свого миленького
Богу помолися.

Стоїть місяць над горою,
Та сонця немає;
Мати сина в дороженьку
Слізно проводжає.

Прощай милий мій синочку!
Та не забавляйся!
За чотири неділеньки
Додому вертайся!

Ой, рад би я, матусенько,
Скоріше вернуться, -
Та вже щось мій вороненький
В воротах спіткнувся.

Ой, Бог знає, коли вернуся,
В якую годину;
Прийми ж мою Марусенку
За свою дитину!

Прийми її, матусенько,
Всі ми в Божій волі.
Бо хто знає, чи жив вернуся,
Чи ляжу на полі?

Ой рада б я Марусеньку
За рідну прийняти,
Та чи буде ж вона мене,
Сину, шанувати?

Ой, не плачте, не журіться.
В тугу не вдавайтесь.
Заграв кінь мій вороненький,
Назад сподівайтесь.','["pisni.org.ua", "cat:lirychni", "cat:narodni", "cat:patriotic", "Пісні про кохання, ліричні", "Народні пісні", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_22993'), datetime('now')),datetime('now'));
