INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2299563','Рідна школа','Музика: Іван Пустовий Слова: Петро Паливода','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Не забуду, мабуть, я ніколи,
Наче скарб, у пам''яті зберіг
Перший день, коли я йшов до школи,
І не чув я під собою ніг.
Так хотів усе на світі знати
Про моря, планети і тварин,
Таємничі землі відкривати,
Мандрувати до чужих країн.

Приспів:
Школа, рідна школа -
Джерело любові,
Хлопчика малого
Мрії веселкові.
На шкільнім подвір''ї
Зустрічі й прощання,
Кличе дзвоник на урок:
Перший та останній.

Як не міг думкам я дати ладу,
Чи не знав чогось, або не вмів,
Подумки летів я на пораду
Знову до своїх учителів.
Школа завжди йде повсюди з нами
Крізь минуле наше й майбуття,
Кожен день складаємо екзамен,
А урок триває все життя.

Приспів','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2299563'), datetime('now')),datetime('now'));
