INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2301797','Пісня про котика Мурчика','Музика: Анна Кривута Слова: Анна Кривута. Виконує: Подих весни','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Є у мене котеня,
Дуже люблю його я,
Хвостик, вушка й лапки |
Котика-царапки.        | (2)

Приспів:
Мурчик, мяв,
Мурчик, мяв,
Вдень він спав,
Вночі бешкетував,
Як побачив мишку,
То скоріш втікав,
Мурчик, Мурчик, мяв!

Тільки сонечко встає,
Він постати не дає,
Все навколо рветься,   |
Котиться і б''ється.    | (2)

Приспів.

Зі стола ковбаску вкрав,
Пінку з молока злизав,
Вусики вмиває,         |
Хитро поглядає...      | (2)

Приспів.

Неслухняне котеня,
Що робити маю я?..
Як йому збагнути -     |
Чемним треба бути!     | (2)

Приспів.

Сальто вверх і сальто вниз
Може Мурчик - наш артист,
Зробим з нього зірку,
Віддамо до цирку!

Приспів.

Свариться уся сім''я,
Захищаю його я:
Він же нечемненький,
Бо іще маленький.

Приспів. (2)','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2301797'), datetime('now')),datetime('now'));
