INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2303354','Ударте в крила','Музика: Юрій Пясецький Слова: Марійка Підгірянка','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ударте в крила,
Орли ви пластові,
Вгору спрямуйте свій лет -
Над наші гори ті горді, чудові,
Над синій неба намет.

Приспів:
Зір свій здіймайте
На досвітні зорі,
В життя найранішій порі,
Бо з скельних гнізд ви,
З карпатських зворів,
А шлях ваш - гей, угорі.

Ударте в крила -
І пітьма загине,
Зима заміниться в яр.
Злітайте в гору,
Ви - плем''я орлине,
І кличте сонце з-за хмар!

Приспів.','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2303354'), datetime('now')),datetime('now'));
