INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2300394','Коли мої друзі зі мною','Музика: Володимир Шаїнський Слова: Михайло Пляцковський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Якщо з одним вийшов в шлях,
Якщо з одним вийшов в шлях -
Веселіше дорога!
Без друзів мене - трохи,
Без друзів мене - трохи,
А з друзями багато!

Приспів:
Що мені сніг, що мені спека,
Що мені дощик проливний,
Коли мої друзі зі мною!

Там, де важко одному,
Там, де важко одному, -
Впораюся разом з вами!
Де чогось не зрозумію,
Де чогось не зрозумію -
Розберемо з друзями!

Приспів.

На ведмедя я, друзі,
На ведмедя я, друзі,
Вийду без переляку,
Якщо з одним буду я,
Якщо з одним буду я,
А ведмідь - без одного!

Що мені сніг, що мені спека,
Що мені дощик проливний,
Коли мої друзі зі мною!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2300394'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2300394','Коли мої друзі зі мною','Якщо з одним вийшов в шлях,
Якщо з одним вийшов в шлях -
Веселіше дорога!
Без друзів мене - трохи,
