INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230055','А в полі, полі сам Господь ходив','Українська народна пісня','uk','ukraine_1991',NULL,'1997','Шевченків край: Історико-культурологічні нариси. - К., 2005. С. 455.','Записали Я Пришедько та М. Музика в Музеї народної архітектури та побуту України від фольклорного колективу с. Дубіївка Черкаського району Черкаської області 1997 року. Розшифрував Л. Ященко. Пісня з добірки Леопольда Ященка.','А в полі, полі сам Господь ходив,
Сам Господь ходив, жито породив,
Жито-пшеницю, всяку пашницю.
Діва Марія за Ним ходила,
За Ним ходила, Його просила:
А вроди, Боже, жито-пшеницю,
Жито-пшеницю, всяку пашницю!

Сію, вію, посіваю,
З Новим Роком поздоровляю!
Многая літа!                |(3)','["pisni.org.ua", "cat:narodni", "cat:shchedrivky", "Народні пісні", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230055'), datetime('now')),datetime('now'));
