INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230212','Під Дубиною під Зеленою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. В Чистому Полі Сам Плужок ходить. Буде Тобі Три Дорозі. Читати листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Стежки до інших листків про Українські традиції.','Під Дубиною під Зеленою

Приспів:
Ой дай Боже!

Там г''оре Плужок ще й Восьмиричок
А за тим Плужком Василь з Батіжком
Прийшов до Нього Батенько Його
Ой ори Синку Дрібненьку Скибку
Будем сіяти Жито-Пшеницю
Жито-Пшеницю всяку Пашницю
Тай накладем Кіп як на Небі Зір
Тай будем возить за Синє Море

Ой дай Боже!','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_230212','Під Дубиною під Зеленою','Під Дубиною під Зеленою

