INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230354','Як ще не було Початку Світа','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Як ще не було Початку Світа — Колядка стародавня: Українське Різдво Світа. Тогди не було Неба ні Землі. Читати листки, де є згадка з приводу цієї Пісні: Українське Свято Воведення 4.12 - Передріздвяний Святочний час. Українські релігійні роздуми про Бога: Яблучко. Стежки до інших листків про Українські традиції.','Як ще не було Початку Світа
Приспів: Гей дай Боже!

То ще не було Неба ні Землі
А лишень було Широке Море
А на тім Морі Явір Зелений
На тім Яворі Три Голубочки
Три Голубочки Раду радили

Як би ми Браття  Світ поставили
Ой ходім Браття аж на Дно Моря
Та там добудем Дрібного Піску
Тот Пісок Дрібний посієм всюди
Та встане з него Свята Землиця

Та буде тамки Золотий Камінь
З того Каміння то буде Сонце
То буде Сонце і Місяць Ясний
Рум''яна Зоря й Звізди Прекрасні','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "Колядки", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230354'), datetime('now')),datetime('now'));
