INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230073','А в Горі в Горі в Глибокім Зворі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Службоньку служив Слізоньку вронив. Сам Сокіл сидить далеко й видить. Честь Богу хвала навіки слава. Буде в Тебе Господь на Вечері. А на Тих Столах Дороге й Пиття. Листки з приводу цієї Пісні: Передріздвяний Святочний час: Упереджуючі знаки, Михайла 21.11. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Прадід і Лицарі. Прабатько – Вчитель, Лицар і Вірник Божий. Сльози і Купіль Господа. Плач Сокола. Українське Різдво Світа: Співаймо Колядки й Щедрівки на Щастя-Здоров''я! (Стародавні Колядки й Щедрівки з нотами і звуковими зразками — Мереживний Збірник) Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда) ― Святий Збір (Трійця) ― Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло. Доба мистецьких і наукових містифікацій? "Вертеп", що це таке? Замінювали народні пісні схоластичними віршами школи. "Отрадный результат нашего движения к коммунистическому обществу".','А в Горі в Горі в Глибокім Зворі
Приспів: Славен єс славен єс Боже
Відміна: Словен єс словен єс Боже

Росте Деревце Тонке Високе
Тонке Високе а вшир широке
А вшир широке а ввись кудряве
А на тім Кудрі Сам Сокіл сидить
Сам Сокіл сидить далеко й видить
Видить в Николи Тисові Столи
Як вконець Стола сидить Никола
Ой сидить-сидить Слізоньку ронить
А з тої Слізки сталося й Море

А по тім Морю пливе й Корабель
А в тім Кораблі Тисові Столи
Позастелені чом Скатерками
Чом Скатерками чом Дорогими
А на тих Столах Дороге й Пиття
Медок-Солодок й Солодка Кутя

Та за цим Столом будь же нам здоров!
Віншуєм тебе Щастям-Здоров''ям
Щастям-Здоров''ям та з цими Святми
Та з цими Святми чом Різдвяними
Чом Різдвяними чом Роковими

Ой здоров-здоров та будь сам з собов
З свойов Ґаздинев та з Діточками
Та з Діточками та з Сусідками
Та з усім Родом близьким й далеким
Близьким й далеким великим й малим

Ой дай ти Боже з Поля доволі
З Поля доволі а в Дім Здоров''я
На Челядочку на Худібочку

Ой що ж ми Тобі колядували
Колядували красно співали
Як Перепілка в Ярій Пшениці
Як Ластівонька в Новенькій Стрісі
Як Соловейко та в Лузі-лузі
Честь Богу хвала навіки слава
Навіки слава навіки слава','["pisni.org.ua", "cat:kolyadky", "cat:krasa-pryrody", "cat:narodni", "cat:philosophic", "Колядки", "Пісні про красу природи", "Народні пісні", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230073'), datetime('now')),datetime('now'));
