INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2303379','Гей, славний наш гурток "Вовків"','Музика: Іван Недільський Слова: Микола Угрин-Безгрішний','uk','ukr_ssr_1919_1991',NULL,'1947','аудіозапис','Пісня Гуртка пл. юнаків "Вовки" у Байроті, створена на еміґрації 1947 року.','Гей, славний наш гурток "Вовків",
В шляхетній дружбі всі живуть.
Дванадцять вірних юнаків -
Нас сіроманцями зовуть...

Для Пласту труд, твердий закон,
Для нас усіх земля свята -
Це край, де Сян, Дніпро і Дон,
