INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230394','Спіте, діти, спіте, любі','Музика: народна Слова: А.Листопад. Виконує: Микола Будник','uk','ukr_ssr_1919_1991',NULL,'1932',NULL,'Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Господа Милосердного прохали та благали. Спіте міцно, спіте, Діти, янгол божий на порозі. І усіх вас Невольників із Темниці випускати. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння. Коляда і Великдень: Різдво і Відродження Світа. Пам''яті жертв Голодоморів. Стежки до листків про Українські традиції. Висловлювання: Чи чує світ? "Дорогі співвітчизники, брати і сестри! В ці дні Україна вшановує пам''ять жертв Голодомору 1932-1933 років. Це наша спільна пам''ять, спільний біль, бо немає в Україні жодного роду, жодної сім''ї, які б не зачепила ця трагедія. Мільйони наших родичів, односельців, земляків, замучених голодом, — це не просто жертви несправедливості режиму. Це — винищені носії наших родинних традицій, моральних підвалин, духовних цінностей". "У 1932-33 роках ми з вами осиротіли майже на 10 мільйонів людей. Третина з них — діти. Ми будемо чутися вічними сиротами у цьому світі, розгубленими і незахищеними на історичних роздоріжжях, доки не станемо однією зрідненою, згуртованою, міцною родиною. Адже усі ми — їхні нащадки, і в нас усіх тече і пульсує одна — їхня — кров. 22 листопада у храмах України пройдуть поминальні служби Божі у пам''ять жертв голодомору. Запалімо ж свічки у кожній церкві, у кожній хаті і всі разом пом''яньмо невинно убієнних наших земляків. Помолімось разом із дітьми й онуками за Царство Небесне для них, як молимося за найрідніших, найближчих, найдорожчих людей". — Звернення Віктора Ющенка ("Наша Україна") у листопаді 2003р. з приводу роковин проти-українського Голодомору-Геноциду 1932-1933 років - http://www.razom.org.ua/viewnews/news/10857 — дивіться також тут','Спіте, діти, спіте, любі, спіть, не просинайтесь!
Вже не буде мучить згуба, забере вас пташка райська.
Спіте міцно, спіте, діти, янгол божий на порозі,
Вже не буде їсти xтітись і не будуть пуxнуть нозі!

Натопила маковинням, затулила лядку й комин
І в тумані темно-синім заспівала колискову:

Спи, синочку, горепаску, засинай навіки, доню,
То моя остання ласка з материнської долоні.
Ще пограймось навперейми у піжмурки із бідою,
Заxоваємось од неї у сиру земельку, лельки!','["pisni.org.ua", "cat:holodomor", "cat:istorychni", "Пісні про голодомор", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230394'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_230394','Спіте, діти, спіте, любі','Спіте, діти, спіте, любі, спіть, не просинайтесь!
