INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2304369','Пісня для дітей про Святого Миколая','Музика: Ігор Білик Слова: Олена Дерваль. Виконує: Сашенька Ціва','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хлоп''ятка і дівчатка
Чекають вже на Тебе,
Аби в цей день щасливий
Прийшов до нас із неба

Приспів:
Святий Миколай!
Святий Миколай!
До нас завітай,
Дарунки лишай!
Малеча слухняна
Чекає до рана,
Тебе, Миколай!

Слухняні ми та чемні,
Вже вміємо читати,
У нічку ту, що темна,
Прийди у нашу хату!

Приспів.

Цукерки і пакунки
Сховав Ти під подушку,
Аби ті подарунки
Знайшли ми з-поза ранку.

Приспів. (2)','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2304369'), datetime('now')),datetime('now'));
