INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2303971','У хатинці','Слова: Марійка Підгірянка. Виконує: Лідія Максимяк','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Тихо, лялю моя, спи,
Надворі гудуть вітри,
Надворі мете снігами,      |
Нам тут добре коло мами... | (2)

