INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2303614','Молитва','(О, пресвятая Богородице Маріє). Музика: Микола Колодочка Слова: Надія Мовчан-Карпусь. Виконує: Нескорені','uk','ukraine_1991',NULL,NULL,'Надала Богдана Сімович',NULL,'О, пресвятая Богородице Маріє,
Народ мій збережи від лиходія,
Від магій чорних, темних чар,
Від міжусобиць і від чвар.
Нехай в землі ржавіють списи,
Нехай відступлять смерті риси,
І не дурманить душу, мов отрута,
Омана люта у хвилини скрути.

О, пресвятая Богородице Маріє,
Народ мій збережи від лиходія.
Нехай на многа-многа літ
Цвіте життя, як дивоцвіт.
Благословен, хто скинув пута,
Повік страждання не забути.
Нехай нам вітер миру тихо віє,
О, Матір Божа, Пресвята Маріє!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2303614'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2303614','Молитва','О, пресвятая Богородице Маріє,
Народ мій збережи від лиходія,
