INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2304797','З Новим Роком, країно!','Музика: Христина Панасюк Слова: Христина Панасюк. Виконує: Христина Панасюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Рік Новий
З ароматом мандарин і шоколаду
Завітав до дорослих і дітей.
За вікном ми, нарешті,
Дочекались снігопаду,
Сніг летить
Вд небес і до людей...

Приспів:
З Новим роком, країно,
З Новим роком!
Хай біда й тривоги оминають дім!
Дід Мороз
Хай в торбинці тихим кроком
Принесе здоров''я,
Щастя вам усім!

Білий сніг, дітвора радіє
Й бавиться завзято,
Звідусіль знов луна
Веселий сміх.
Ми усі з нетерпінням
Дочекалися на свято,
Чудеса на Різдво
І Новий рік!

Приспів. (2)','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2304797'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2304797','З Новим Роком, країно!','Рік Новий
