INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2304899','Святий Миколай йде з високого неба','Музика: Галина Терлецька Слова: Марійка Підгірянка','uk','ukraine_1991',NULL,NULL,'http://www.studijadm.lviv.ua/?page_id=366',NULL,'Святий Миколай йде
