INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2304818','Вже не той','Музика: Ілля Найда Слова: Ілля Найда. Виконує: Ілля Найда','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Не сталось так, як я того хотів...
Прийшла біда - минулося кохання.
А, може, це була лиш гра така,
Для тебе це гра, для мене - життя,
Для мене - кохання...

Приспів:
Може, я вже не той,
Може, й ти вже не та,
Може, й немає у нас того кохання?..
Питаю знову і знов -
"Де знайти ту любов?"
Що я дарував, тобі дарував
Із ночі до рання...

Я прочитав - "Любов живе три літа",
А, може, став для тебе я не тим,
Та я не перестав тебе любити,
Повернись, пробач, не йди...

Приспів. (2)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2304818'), datetime('now')),datetime('now'));
