INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230910','А в Нашого Пана серед Двору Древо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','А в Нашого Пана серед Двору Древо — Колядка стародавня: Українське Різдво Світа. Рай розвився Господь звеселився. Листки з приводу цієї Пісні: Бог, Різдво Світа, Дідух і Лицарі. Українські релігійні роздуми про Бога: Яблучко. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','А в Нашого Пана серед Двору Древо
Приспів: Щедрий Вечір Добрий Вечір !

Молодий Іванко вружжо заряджає
Вружжо заряджає на Орла стріляє

Не стріляй на мене Молодий Іванку
Тай буде на тебе тай Три Погодоньки
Що Перва погода Сніг та Метелиця
Як Друга погода Срібен Дощик іде
Що Третя погода Ясне Сонце світить','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "Колядки", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230910'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_230910','А в Нашого Пана серед Двору Древо','А в Нашого Пана серед Двору Древо
