INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2303910','Пісня для дітей про святого Миколая','Музика: Віталій Кобринович Слова: Анна Канич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сьогодні до очей твоїх
Святкові злинуть сни,
І ступить гість на твій поріг,
Ангелики із ним.
Це ніччю Миколай прийде,
Наш Миколай Святий,
І подарунок покладе,
Якщо заслужиш ти!

Приспів:
Миколай, наш Святий Миколай,
Завітає у рідний наш край!
Непомітно він зайде у кожен дім,
Щоб життя звеселити усім!

Він любить чемних всіх дітей,
Жаліє вдів, сиріт,
Рятує на землі людей
Від злиднів, горя, бід.
В ту ясну ніч, в святковий час
Він ступить на поріг.
Де Миколай іде до нас
Крізь тисячі доріг.

Приспів. (2)','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2303910'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2303910','Пісня для дітей про святого Миколая','Сьогодні до очей твоїх
Святкові злинуть сни,
І ступить гість на твій поріг,
Ангелики із ним.
Це ніччю Миколай прийде,
Наш Миколай Святий,
І подарунок покладе,
Якщо заслужиш ти!

Приспів:
Миколай, наш Святий Миколай,
Завітає у рідний наш край!
Непомітно він зайде у кожен дім,
Щоб життя звеселити усім!

Він любить чемних всіх дітей,
Жаліє вдів, сиріт,
Рятує на землі людей
Від злиднів, горя, бід.
В ту ясну ніч, в святковий час
Він ступить на поріг.
Де Миколай іде до нас
Крізь тисячі доріг.

Приспів. (2)');
