INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230890','Через Наше Сельце везли Клен Деревце','Українська народна пісня. Виконує: Ніна Матвієнко','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пара - любощі: Сельце-Деревце. Церковця-Дзвіниця. Свічечка-Дзвоник. Вибір Пари. Астральні Заручини — Українське містичне Весілля: / Купала. Еротика, жарти, забави: Катерини –... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... –... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. А з того Деревця строїли Церковцю. Були Світилки Яснії Зірки. А в тії Церковці Три Свічечки Ясні. А в тії Дзвіниці Три Дзвоники Гласні. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Через Наше Сельце везли Клен-Деревце
Приспів: Дерево Клен-Дерево Дрібне Зелененьке | (2)

А з того Деревця строїли Церковцю
А в тії Церковці Три Свічечки Ясні
Перша свіча ясна то Ніночка Красна
Друга свіча ясна то Ганнуся Красна
Третя свіча ясна то Улянка Красна

Через наше Сельце везли Клен-Деревце
А з того Деревця строїли Дзвіницю
А в тії Дзвіниці Три Дзвоники Гласні
Перший дзвоник гласний то Іванко Красний
Другий дзвоник гласний то Андрійко Красний
Третій дзвоник гласний то Петрусик Красний','["pisni.org.ua", "cat:kupalski", "cat:shchedrivky", "Купальські пісні", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230890'), datetime('now')),datetime('now'));
