INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230971','Ой у Лісі й у Лісі на Дубку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','(с. Комарівка, Бучанський район, Київська область) Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Були Світилки Яснії Зірки. Шиє-малює Злотом гаптує. Там повісив Хлопчина Гойдалку. Листки з приводу цієї Пісні: Бог, Різдво Світа, Дідух і Лицарі. Українські Свята Різдва Світа і Щедрого Вечора. Староукраїнські релігійні роздуми про Бога: Яблучко. Що означає ім''я "Коляда"? Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой, у Лісі й у Лісі на Дубку,
Там повісив Хлопчина Гойдалку.

Гойдайте мене й високо,
Ой, щоб було видненько далеко.

Де моя Тещонька мед-вино п''є,
Де моя Дівчина Вінка в''є.

Ой, де моя Дівчина походжає,
Вишитими рукавами й махає.

Чорними бровами і моргає,
Тай до себе Хлопчину гукає.

Ой, до мене, Хлопчино, до мене,
Чорниє брівоньки й у мене!','["pisni.org.ua", "cat:kupalski", "cat:zeleni-svyata", "Купальські пісні", "Пісні до Зелених свят"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_230971'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_230971','Ой у Лісі й у Лісі на Дубку','Ой, у Лісі й у Лісі на Дубку,
