INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_230990','Голубка','Виконує: Володимир Шинкарук, Ірина Шинкарук','uk','ukraine_1991',NULL,'1993','Аудіо-збірка "Ірина та Володимир Шинкаруки" (1993-2001)','Текст і акорди записано на слух за джерелом 1. Оригінальна тональність: A#m (каподастр на I ладі). В джерелі пісню датовано: 1993. * Перша строфа співається без акомпанементу. Один із використаних акордів: E7* [0 2 0 x 3 0] Підбір акордів: bohdanko (pisni.org.ua)','Голубка біла
