INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231199','Люлі Люлі Старий Гулю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Колискові: Світові-Дитині. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Ходить Котик по Плоточку. Листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Співаймо Світові-Дитині: Колядки, Щедрівки та Колискові. Стежки до листків про Українські традиції. Висловлювання: Тримаймося Пісень. Якби можна було повернутися в ті часи, коли всі і скрізь співали, і до кожної нагоди життя були свої пісні! – Колись селянин, тепер начальник управління.','Люлі-люлі Старий Гулю
Лізь на Вишку по Цибулю
Не полізу бо боюся
Впаду з Вишки тай заб''юся

Люлі-люлі Старий Басе
Лізь нагору по Ковбаси
Зараз тільки з Печі встану
Може якось їх дістану','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231199'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_231199','Люлі Люлі Старий Гулю','Люлі-люлі Старий Гулю
