INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2308010','Котився вінець з поля','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Пісні Явдохи Зуїхи / Запис. Гнат Танцюра. - Київ: Наукова Думка, 1965. - 812 с.',NULL,'Котився вінець з поля,
Котився вінець з поля,
Закотився до голови двору.

Жніте, женчики, жніте,
Жніте, женчики, жніте
І віночок плетіте.

Віночок пелихатий,
Віночок пелихатий,
Наш господар багатий.

А господиня пишна,
А господиня пишна
Проти женчиків вийшла.

Женчики мої милі,
Женчики мої милі
Що ви в полі робили?

Чи спали, чи лежали,
Чи спали, чи лежали,
Чи пшениці дожали?

Ні спали, ні лежали,
Ні спали, ні лежали,
Ми пшениці дожали.

А господиня багата,
А господиня багата,
Зарізала гусака.

Зарізала ще й гуску,
Зарізала ще й гуску
Женчикам на закуску.','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2308010'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2308010','Котився вінець з поля','Котився вінець з поля,
Котився вінець з поля,
Закотився до голови двору.

Жніте, женчики, жніте,
Жніте, женчики, жніте
І віночок плетіте.

Віночок пелихатий,
Віночок пелихатий,
Наш господар багатий.

А господиня пишна,
А господиня пишна
Проти женчиків вийшла.

Женчики мої милі,
Женчики мої милі
Що ви в полі робили?

Чи спали, чи лежали,
Чи спали, чи лежали,
Чи пшениці дожали?

Ні спали, ні лежали,
Ні спали, ні лежали,
Ми пшениці дожали.

А господиня багата,
А господиня багата,
Зарізала гусака.

Зарізала ще й гуску,
Зарізала ще й гуску
Женчикам на закуску.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2305563','Ой, як крикне старий орел',NULL,'uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ой, як крикне старий орел,
Щo під хмари в''ється,­
Гей, загуло Запоріжжя,
Бо до ради тнеться.

Сірко славний серед кола
Раду оглядає,
Товариство привітає
Та й так промовляє:

"Гей, панове-запорожці!
Татарва лякає,
Не вдаваймось у дурницю,
Бо якраз злапає!

По збирайтесь зараз сотні
І сідлайте коні,
Та чекайте отамана,
Отам на вигоні!"

Як прилинув козак Сірий
На сивому коні:
"Нумо, славні запорожці,
Ходім в чисте поле!"

Ой, як крикне старий орел
Попід небнім склоні,
Спинилися запорожці
Попасати коні.

А як крикне старий орел,
На шпиль-гору сівши,
Засумили запорожці,
Коней погубивши.

"Батьку, славний отамане!
Що маєш робити?
Без коня ти що такеє?­
Як орел підбитий!"

Зажурився козак Сірий
Проміж козаками,
Як вит лонька засумилась
Проміж ясенками.

Ось прилинув козак з варти,
Де займані коні:
"Не журися, отамане,­
Коні вже в загоні!"

"Ой братику ж мій завзятий.
Запорожець милий!
Кажи ж хутчій, чи жив ще мій
Кониченько сивий?"

"Та жив, здоров, і  всі цілі
Твої запорожці;
Тільки ж трошки потрощили
Татарюзі кості!"

Зареготався отаман:
"Добре, пани-брати!
Ну, тепер же ми ходімо,
Рушайте ж гармати!"

Загудів стан запорізький,
Як Чорнеє море,­
Понеслися запорожці
Облавою в поле ...

Ой, не вітер в полі грає,
Не орел літає -
Ото ж Сірин з товариством
По степу гуляє!','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2305563'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2305563','Ой, як крикне старий орел','Ой, як крикне старий орел,
Щo під хмари в''ється,­
Гей, загуло Запоріжжя,
Бо до ради тнеться.

Сірко славний серед кола
Раду оглядає,
Товариство привітає
Та й так промовляє:

"Гей, панове-запорожці!
Татарва лякає,
Не вдаваймось у дурницю,
Бо якраз злапає!

По збирайтесь зараз сотні
І сідлайте коні,
Та чекайте отамана,
Отам на вигоні!"

Як прилинув козак Сірий
На сивому коні:
"Нумо, славні запорожці,
