INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231414','Благослови Мати Весну закликати','Українська народна пісня. Виконує: Злата','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Пара — любощі: Мати. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Вже Весна воскресла. Благослови Мати Весну закликати. Гаївоньку починаймо у Добрий Час. Дай нам Доле Довгий Вік. Под же Дівча медже Нас. Щоб на Нашій на Веснянці збиралася збірна. Бердо Бердо Бердовичко Благослови Мати Весну закликати Благослови Мати Весну закликати (2) Весняночка Паняночка хто по Тобі ходить Вийди вийди Іванку Вийди вийди Іваночку Де Гаївка лунала Там Діброва палала Добрий День Марійко маєш Дочок стілько Ой як вийду ой як крикну догадайся Травко Муравко чом ти ни зелена Кругом Нього зелененько всередині веселенько. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Про Українські назви місяців Марець і Май. Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські традиції. ВИСЛОВЛЮВАННЯ: Храм Добра. Я гадаю, що ціль усіх великих релігійних звичаїв – не строїти великі храми назовні, але творити храми добра та співчуття всередині, в наших серцях. — Далай-лама Пісні — душа Українського народу. Піснї україньско-руского народа вяжуть ся тісно з єго житєм і подають вірне з''ображенє народного побуту від найдавнїйших часів, відколи нарід почав себе тямити, аж до нинїшного дня; у піснях зложив нарід свою сповідь, відкрив свою душу, виявив свободолюбні змаганя та зобразив вірно свою вдачу. Через народні піснї вчимо ся пізнавати людску душу, учимо ся розуміти і любити людий та цінити в кождім чоловіцї те, що в нїм є людского: наша народна поезия має образуючий і виховуючий вплив на широкі маси народу і ріжні єго верстви. Народні піснї — се неначе національна біблїя україньско-руского народу, се книга мудрости, у якій зложив нарід плоди свого довговікового досьвіду і тисячлїтної культури. Україньскі народні піснї визначають ся прекрасною формою пісенного складу і незвичайним богатством поетичного вислову. Християньске духовенство в інтересї церкви старало ся викоріняти серед народу давну віру, заказуючи і виклинаючи стародавні обрядові піснї, як "бісовскія пінія" або приноровлюючи сї піснї до християньских сьвятих і празників. Таким чином заведенє й розширенє християньскої віри спинило розвій давної релїґійної поезиї, а само християньство не змогло уже витворити у нас своєрідної національної поезиї релїґійної. — Степан Дубравський','Благослови Мати Весну закликати
