INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231498','Чом ти не прийшов?','Українська народна пісня. Виконує: Гурт "Експрес"','uk','ukraine_before_1917',NULL,NULL,NULL,'Див. спільні мотиви у пісні: Тече річенька невеличенька.','— Чом ти не прийшов, як місяць зійшов,
Як я тебе чекала?
Чи коня не мав, чи стежки не знав,
Мати не пускала?

- І коня я мав, і стежку я знав,
І мати пускала,
Найменша сестра, бодай не зросла, —
Сідельце сховала.

А старша сестра сідельце знайшла,
Коня осідлала.
- Ой їдь, братику, до дівчиноньки,
Що тебе чекала.

— Тече річенька невеличенька,
Схочу - перескочу.
Віддай же мене, моя матінко,
За кого я хочу.

Віддала мене, моя матінка
За діда старого
Казала менішанувать його
Так як молодого

Шанувала рік, шанувала два,
третій не стерпіла.
Перекинулась в сиву зозулю
Тай в світ полетіла.

Гаєм летіла, землю кропила
Дрібними сльозами.
Гаєм летіла, гілля ламала
Білими руками.

Прилетіла в сад та й стала кувать
В саду на калині.
Та й стала кувать, жалю завдавать,
Горе на чужині','["pisni.org.ua", "cat:lirychni", "cat:narodni", "Пісні про кохання, ліричні", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231498'), datetime('now')),datetime('now'));
