INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23091','Там під Львівським замком','Українська народна пісня','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,NULL,'Повторення - на зразок першого куплета','Там, під Львівським замком, старий дуб стоїть.
Там, під Львівським замком, старий дуб стоїть.
А під тим дубочком січовик лежить.
Там, під Львівським замком, старий дуб стоїть.
А під тим дубочком січовик лежить.

Він лежить не дише, він неначе спить.
Золоті кучері вітер шелестить.

А над ним старенька матінка стоїть.
І до нього стиха слова говорить:

"Сину ж ти, мій сину, дитино моя.
Були б тя не вбили, якби не війна.

Було вас у батька  п''ятеро синів.
Ти був наймолодший, сину мій Андрій.

Як ти був маленьким, батько воював.
Він за Україну голову поклав".

А позаду неньки отаман стоїть.
І до неї стиха слова говорить:

"Hе плач, стара мати - син героєм став,
Він за Україну голову поклав".

Висока могила, хрест березовий.
А на тому хресті тризуб золотий.    Фонограма-мінус (mp3, 320 kbps). весільний вальс','["pisni.org.ua", "cat:narodni", "cat:patriotic", "cat:strilecki", "Народні пісні", "Патріотичні пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23091'), datetime('now')),datetime('now'));
