INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231420','Вийди вийди Іваночку','Українська народна пісня. Виконує: Ніна Матвієнко, Тріо "Золоті Ключі"','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Пара — любощі: Вінок - Золотий Кілок. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... Наспів цієї Веснянки є основою Фіналу 1-го Концерту для фортеп''яно з оркестром Петра Ілліча Чайковського, у цьому Концерті використано й інші Українські наспіви. Вже Весна воскресла. Кругом Нього зелененько всередині веселенько. Благослови Мати Весну закликати. А Дівчатам по Віночку. Листки з приводу цієї Пісні: Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень: Українське Свято Відродження Світа. (Вибір Пісень) Про Українські назви місяців Марець і Май. Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські традиції. ВИСЛОВЛЮВАННЯ: Тримаймося Пісень. Гадаю, ми виживаємо завдяки силі нашої культури. Завдяки нашій духовності, вкоріненій у землю. Завдяки доброті, незлопам''ятності та щедрості в нашій пісенній вірі. - Стара людина, митець, той, хто співає.','Вийди-вийди Іваночку
Заспівай нам Весняночку
Зимували не співали
Весни дожидали

Весно Весно наша Весно
Да що Ти нам та принесла
Старим Бабам по Кийочку
А Дівчатам по Віночку

Відміна 1:

Ой Вінку Наш Вінку
Хрещатий Барвінку
А я Тебе плела
Та вчера-з-вечера
Та повісила-м Тебе я
В Теремі тай на Дереві
На Шовковім Шнурочку
На Золотім Кілочку

А моя Мати взяла
Та Миленькому дала
Коли б я була знала
Була б я ''го краще вбрала
Ще й Золотом назолотила
Миленького прикрасила

Відміна 2:

Звила я Віночок вчора
Ізвечора-ізвечора
З Зеленого Барвіночку
Тай повісила на Кілочку

А Матуся Моя вийшла
Та Віночок Зелен зняла
Та Віночок Зелен зняла
Тай Нелюбові дала

Ой коли б я теє знала
Я би Його розірвала
Я би Його розірвала
Ніж Нелюбові дала','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231420'), datetime('now')),datetime('now'));
