INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2315910','Героям Слава','Музика: Слава Баштовий, Олександр Гертіх Слова: Слава Баштовий. Виконує: Слава Баштовий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли закінчиться війна,
Вона така для всіх страшна,
Ми маєм жити добре,
За нами перемога!
А ти чекай мене, мала,
Молитву прочитай до сна,
Про Бога забувати
Не треба нам ніколи!

Приспів:
Героям Слава!
Героям нашим Слава!
За незалежність нашу
В землю полягли!
Героям Слава!
Слава Україні!
Живим і мертвим
Слава назавжди!

В тім бою я переміг,
А мій найкращий друг поліг.
За вільну Україну
Навіки йому Слава!
А в нього вдома дітки є,
Та як їм розповісти те,
Що більше їх не зможе
Обняти рідний татко?..

Приспів.

Скоро тим усім катам,
Які зробили горе нам,
Прийдеться відповісти
За скоєне навмисно.
За те, як славні козаки
Лишились в полі на завжди,
Ніколи не забудем ми,
Піднімемо за них чарки!..

Приспів.

Героям Слава!
Героям нашим Слава!
Як і на небі
Так і на землі
Ми не забудем
І будем пам''ятати!
В книжки запишуть вас,
Бо вічні Ви й живі!..','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2315910'), datetime('now')),datetime('now'));
