INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231251','Прийшла Весна з Квітками','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Прийшла Весна з Квітками — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Хто Дудочку зробив Пісеньку навчив. Гляди Сопілоньку щоб гарненько грала. Кругом Нього зелененько всередині веселенько. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські традиції. Отак-то, мої любі. Як забудемо свої пісні-звичаї, забудемо отця-неньку, то бути нам у проваллі, а то просто на смітнику. Танцювати під чужу дудку, тягнути чужий віз. Не з одним таке сталося. Як не хочемо того собі, то тримаймося своїх пісень. – Та, хто співає.','Бадьоро:

Прийшла Весна з Квітками
Всі Парубки з Дівками
На Гойдалках гойдаюцця
Крашанками товкаюцця

Повільніше:

Обицькії Парубки
Усе грають на Дудки
А Степаньо не грає
Бо женитися має

Перший рух:

Кинув дудку у говес
Сам поїхав у Гадес
Продавати Пшеницю
Купувати Спідницю

Повільніше:

Ще й Пшениці не продав

Поступово приспішуючи:

Ще й Спідниці не набрав
А вже Молоденьку
Марусю сподобав','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231251'), datetime('now')),datetime('now'));
