INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231717','Ой Дібровонько Зелена чого рано спустошена','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Ой Дібровонько Зелена чого рано спустошена — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Прийди-прийди Серденя на Пухові Подушки. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Ой Дібровонько Зелена чого рано спустошена','Ой Дібровонько Зелена чого рано спустошена
Рано мене викошено і тим мене спустошено
Прошу тебе Дівчинонько посій по мені Травоньку

Ой рада б я посіяти стоїть нелюб коло Хати
Кличе Мати із кімнати нелюбові постіль слати
А я йому постіль стелю тай клену на всю оселю
Під голову каміняччя а під боки кореняччя
Ще й з кропиви тверді мати щоби було твердо спати

Ой Дібровонько Зелена чого рано спустошена ?
Рано мене викошено і тим мене спустошено
Прошу тебе Дівчинонько посій по мені Травоньку

