INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231726','Ой Дівчина-Орлиця до Козака горнецця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002 2. Перлини української народної пісні. - К.: Музична Україна, 1989','Ой Дівчина-Орлиця до Козака горнецця — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Прийди-прийди Серденя на Пухові Подушки. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Ой Дівчина-Орлиця до Козака горнецця -->','Ой Дівчина-Орлиця до Козака горнецця
А Козак як Орел як побачив дак і вмер

Ой Козаче-Молодче пригорнися солодче
Козак гарно пригортає аж серденько завмирає

Чи чуєш ти Дівчино чи чуєш ти Рибчино
Мати тебе шукає Батько грима гукає

Ой не гримай Батеньку ой не шукай Матінко
Притулилась прилягла вже Орлиця до Орла','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231726'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_231726','Ой Дівчина-Орлиця до Козака горнецця','Ой Дівчина-Орлиця до Козака горнецця
А Козак як Орел як побачив дак і вмер

Ой Козаче-Молодче пригорнися солодче
