INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231797','Сидить Качур в Гороховім Вінку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Сидить Качур в Гороховім Вінку — Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Качата-Гусята усі Гори вкрили. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Сидить Качур в Гороховім Вінку','Усі беруться за руки, йдуть по Колу й співають.
У середині Кола ходить Качур
і вибирає собі найкращу Дівку:

Сидить Качур - 2
В Гороховім Вінку - 2
Вибирай си Качурику
Щонайкращу Дівку - 2
Щонайкраща найладніша
Степанова Дівка - 2

Після того, як Качур вибрав найкращу Дівку,
гурт співає уже Дівчині:

Ой Пташино - 2
Золотії Перця - 2
Вибирай си а би був Ти
Миленький для Серця - 2

Дівчина виводить Хлопця всередину Кола.
Гра повторюється досхочу.','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231797'), datetime('now')),datetime('now'));
