INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2318012','Донечка','Музика: Анна Олєйнікова Слова: Євгенія Левченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я живу у мами й тата
У маленькому селі.
Я весела і завзята,
І щодня у мене свято,
Бо люблю матусю й тата
Більше всього на землі!

Приспів:
Ось така я Олечка,
В тата й мами - донечка!
Сяю я їм сонечком,
А вони - мені.
Мама, тато й донечка
Разом аж три сонечка, -
Це насправді, це насправді,
Справді, а не в сні!

А коли раненько встану,
Посміхаються мені
Всі віконечка у хаті
І ведмедики кудлаті,
Бо люблю матусю й тата
Більше всього на землі!

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2318012'), datetime('now')),datetime('now'));
