INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231512','Іванку, Іванку','Українська народна пісня. Виконує: Гудаки, Андрій Мільчук','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Іванку, Іванку,
З того боку ярку,
З того боку ярку.
Прийшла бим до тебе,
Прийшла бим до тебе,
Взяла вода лавку.

Лавочка тоненька,
Вода студененька,
А я молоденька.
Могла б ся зломити,   | (2)
Жаль мі ся втопити.

Іванку, вечерком,
Прийди до ня тайком.  | (2)
Дам я тобі знати,
Коли вийдуть з хати
І няньо, і мати.

На плоті солома,
Не йди - старі дома.  | (2)
А як буде сіно,       | (2)
Можеш зайти сміло.

Приходи тихенько,
Як стане темненько.   | (2)
Ворота скрипливі,
Сусіди брехливі,
Варуйся серденько.

На ярку, на ярку
Взяла вода лавку.     | (2)
На крилах кохання     | (2)
Прилети Іванку.

Кохання, кохання,
Дівоче страждання.    | (2)
Лем раз любовання,    | (2)
А сто раз чекання','["pisni.org.ua", "cat:lirychni", "cat:narodni", "Пісні про кохання, ліричні", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231512'), datetime('now')),datetime('now'));
