INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23165','Чорна рада','Музика: Ігор Особік Слова: Ігор Особік. Виконує: Андрій Хавунка','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського Братства Львівської політехніки.- Львів, 2000.',NULL,'Em
Трем по землі від коней та піших,
Гомін поважний мужів відважних -
H7
Важлива подія для Січі по землі.
Em
Гучно лунають навкруги тулумбаси.
Козаків скликають до Чорної ради,
H7
На праведний суд закликають вони.

Похмурі обличчя на вмісткім майдані,
І вітер ворушить чорні та сиві чуби.
Скільки на смерть кошових отаманів
Звідси пішло - пам''ятають старі козаки.

"Кладу булаву і дякую за уряд", -
І вже він козак, такий як усі.
Кладу ваш пернач і дякую за уряд,
Писар, хорунжий, полковники всі, як один.
H7
Кладу перо і каламар і дякую за уряд.

Приспів:
Чорна рада - рада правди,
Чорна рада - правди біль.
Хай Чорна рада стратить зраду,
Хай Чорна рада змиє кров,
Em
Священную кров.

Крекнувши в долоню і розправивши вуса,
Починає найстарший закон однозначний,
Старший у літах, у війнах сповитий вояк.
Він ходив на кримчана і на султана,
На льоту ловить стріли, зна цілющеє зілля,
Вивчив прадідів мудрість, козак.

Як водиться здавна з голови починають.
Чи є на нім зрада, чи кревні гріхи?
Чи даремно за нього не пропали козаки?
Чи не продавсь він туркам, чи Польщі, чи часом Москві?

Приспів.

То було за ладом, що тримався справно
Не рік і не два, а цілі віки.
Чи не час нам сьогодні, шановна громадо,
Завести в життя ці закони дідів.

Приспів:
Чорна рада - рада правди,
Чорна рада - правди біль.
Хай Чорна рада стратить зраду,
Хай Чорна рада змиє гріх,
Цей облудливий гріх.','["pisni.org.ua", "cat:bardivski", "cat:istorychni", "Бардівські пісні", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23165'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23165','Чорна рада','Em
Трем по землі від коней та піших,
Гомін поважний мужів відважних -
H7
Важлива подія для Січі по землі.
Em
Гучно лунають навкруги тулумбаси.
Козаків скликають до Чорної ради,
H7
На праведний суд закликають вони.

Похмурі обличчя на вмісткім майдані,
І вітер ворушить чорні та сиві чуби.
Скільки на смерть кошових отаманів
Звідси пішло - пам''ятають старі козаки.

"Кладу булаву і дякую за уряд", -
І вже він козак, такий як усі.
Кладу ваш пернач і дякую за уряд,
Писар, хорунжий, полковники всі, як один.
H7
Кладу перо і каламар і дякую за уряд.

Приспів:
Чорна рада - рада правди,
Чорна рада - правди біль.
Хай Чорна рада стратить зраду,
Хай Чорна рада змиє кров,
Em
Священную кров.

Крекнувши в долоню і розправивши вуса,
Починає найстарший закон однозначний,
Старший у літах, у війнах сповитий вояк.
Він ходив на кримчана і на султана,
На льоту ловить стріли, зна цілющеє зілля,
Вивчив прадідів мудрість, козак.

Як водиться здавна з голови починають.
Чи є на нім зрада, чи кревні гріхи?
Чи даремно за нього не пропали козаки?
Чи не продавсь він туркам, чи Польщі, чи часом Москві?

Приспів.

То було за ладом, що тримався справно
Не рік і не два, а цілі віки.
Чи не час нам сьогодні, шановна громадо,
Завести в життя ці закони дідів.

Приспів:
Чорна рада - рада правди,
Чорна рада - правди біль.
Хай Чорна рада стратить зраду,
Хай Чорна рада змиє гріх,
Цей облудливий гріх.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2317471','Музика слова','Музика: Анна Олєйнікова Слова: Євгенія Левченко. Виконує: Зразковий театр української пісні Джерельце','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ллється музика слова
Так чарівно, казково.
Напрочуд загадково,
Наче серця струна.
Мила, ніжная мово,
Оживаєш ти знову
Голосними струмками,
Наче рання весна.

Приспів:
Моя ти рідна
Українська мово,
Твоє чарує
Мелодійне слово.
Твоє звучання
Кришталсво-чисте,
Твої слова -
Мов зоряне намисто.

Ти дзвениш над полями,
Над лугами, лісами
Ніжним голосом мами,
Що маля забавля.
Лине хай на Вкраїну:
"Очі карі та сині" -
Хай і доньці, і сину
Душу спів звеселя.

Приспів.','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2317471'), datetime('now')),datetime('now'));
