INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2316717','Мамині очі','Музика: Я. Смирнов Слова: Я. Смирнов. Виконує: Софія Яремова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'День наче як день
І все так, як завжди,
Скільки у світі пісень,
Що мені дарувала ти,
Скільки у світі пісень,
Стільки ж у неба зірок.
І кожен шукає свою
І до неї свій робить крок.
Так само і я хочу знайти свою,
Ця пісня моя про те,
Що тебе я люблю!

Приспів:
Мамині очі! Мамині очі!
У світі лише одні!
Мамині очі! Мамині очі!
Щасливі, або сумні...
Мамині очі! Мамині очі!
Світло мого життя...
Мамині очі,
Ви найдорожчі усього,
Що маю я!..

День наче як день
І все так, як завжди,
Вже й вечір прийде
І запалить на небі зірки.
Як перша зійде,
Я до неї звернусь:
Щастя попрошу тобі
Ніби в очі твої подивлюсь.
Так само, як ти,
Щастя просиш мені,
Хай щастя знайде кожен
Хто хоче знайти...
Я знаю, що ти
Щастя просиш мені,
Та я за все, що є
Дякую, мамо, тобі!..

Приспів.

Мамині очі! Мамині очі!
Мамині очі! Мамині очі!

Приспів.

Мамині очі,
Ви найдорожчі усього,
Що маю я!..','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2316717'), datetime('now')),datetime('now'));
