INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232313','Учора звечора з Небесного Двора','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Пречиста Діва Сина рождає. Листки з приводу цієї Пісні: Українська традиція Святого Збору. Святий Збір як політичний ідеал: Що таке Кийовство? Стежки до інших листків про Українські традиції.','Учора звечора            | (2)
