INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232114','Чиї Коні на вигоні мої у Садочку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Правой ручкою обняла ще й поцілувала. Спутай Коня на Отаву в залізнії пути. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Чиї Коні на вигоні мої у Садочку
Ой хто любить далекую а я Сусідочку

Любив би я далекую дак мій рід не велить
Як побачу сильно плачу аж живіт болить

Ой як я люблю поможи Боже
Буду тебе цілувати поки Сон зможе

І націлувався і намилувався
Як у Саду Соловейко Ягод надзьобався','["pisni.org.ua", "cat:vesnyanky-hayivky", "cat:zeleni-svyata", "Веснянки та гаївки", "Пісні до Зелених свят"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_232114'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_232114','Чиї Коні на вигоні мої у Садочку','Чиї Коні на вигоні мої у Садочку
