INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_231899','Ой піду я до Млина до Млина (1)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Еротика, жарти, забави: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Там то Мамко Мельник! Коло Млина Калина Ой піду я до Млина (1) Ой піду я до Млина (2) Ой піду я до Млина до Дірявого Ой піду я до Млина до Млина (1) Ой піду я до Млина до Млина (2) Очерет тріщит Осока плющит Посилала мене Мати Тече Вода Каламутна Як поїхав Мій Миленький до Млина У Перетику ходила По Оріхи Мірошника полюбила Для потіхи Мельник меле-шеретує Обернеться-поцілує Для потіхи У Перетику ходила По Опеньки Лимаренка полюбила Молоденька Лимар Кичку зашиває Мене горне-обнімає Молоденьку У Перетику ходила Я по Дрова Та Бондаря полюбила Чорноброва Бондар Відра набиває Мене горне-пригортає Чорноброву Коли хочеш добре знати Моя Мати Кого будеш попереду Зятем звати Усіх-усіх Моя Мамо У Неділеньку Зятями Будеш звати Тарас Шевченко. Кобзар. Київ, "Дніпро" 1989. с. 370. Лимар, римар — майстер, який виготовляє ремінну збрую. Запозичено з нім. мови, можливо, через посередництво польської, нвн. Ríemer "лимар" пов''язане з Ríemen "ремінь", до якого зводиться й укр. ремінь. С. 233: Етимологічний словник української мови. Т. 3 (Кора-М). Київ "Наукова Думка" 1989. 549с. Кичка — подушечка, прокладка в хомуті. С. 526: Кобзар. Київ, "Дніпро" 1989. Кика — головний убір, що надівається молодій на другий день після вінця; [кичка] — старовинний головний убір заміжньої жінки; віхтик льону, заплетений у косу нареченої; повстяна прокладка під хомутом; кільце для зачіски; пучок пір''я на картузі; пучок соломи або очерету для покриття даху; земляний горб; [кічка] — віхтик льону, заплетений у косу нареченої; дерев''яна цурка для гри; задня частина воза; різновид воза"... С.431: Етимологічний словник української мови. Т. 3 (Кора-М). Київ "Наукова Думка" 1989. 549с. Перетика — перелісок, лісосмуга:-) С. 526: Кобзар. Київ, "Дніпро" 1989. Перетик, наголос на другому складі, — різновид домотканого полотна, що перетикається кольоровою чи якою відмінною смужкою. З нього шиють утиральники, настільники, інколи сорочки. Смужки "перетику" чередуються на полотні в середньому — 70-100 см одна від одної. На пошитих з полотна утиральниках вона припадає на краї, а на настільниках — краї і середину. Коли з "перетику" шиють сорочку, то смужка оперізує поділ, полички та краї рукавів. Сама смужка, яка може бути символом води, у пошитті є найпростішим оздобленням-оберегом. Звичайно, з "перетику" шиють сорочки лише на будень, святкову — обов''язково оздоблюють вишивкою. Зовсім неоздобленого одягу за звичаєм не носили. С. 5: Надія Данилевська, Микола Ткач. Перетик. Фольклорно-етнографічний портрет українського села. Село Сахнівка, Менського району на Чернігівщині. Київ, Український центр духовної культури. 2000. 211с. Відміни. 1. Пішла Дівка до Млина в Неділю На Мельника мала всю надію Там-то Мамцю Мельник Там-то Круподерник На Животі Крупи тре А Мірочки не бере 2. Таке Мати Мельник Таке Круподерник І наварив Галушок І настелив Подушок І Подушка Мяхкенька І Табачка Товстенька Українські сороміцькі пісні. Упор., передмова "Таємничий дивосвіт Українського Еросу" та прим. М.М. Красикова. – Перлини української культури. Харків "Фоліо" 2003. 288с. Читати листки з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Ой піду я до Млина до Млина
А у Млині Новина-новина

Приспів: Там-то Мамко Мельник
Там-то Мамко гарний
Там-то Мамко хороший
Меле Гречку без грошей

Меле-меле насипа-насипа
Тай на мене погляда-погляда

Меле-меле підсипа-підсипа
Як поверне пригорта-пригорта

Меле-меле шеретує-шеретує
Як  поверне поцілує-поцілує

Він Мірочки не бере не бере
Як на Крупу подере-подере

А вже Гречка на Коші на Коші
Припав Мельник до душі до душі','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_231899'), datetime('now')),datetime('now'));
