INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2321394','Канікули','Музика: Анна Олєйнікова Слова: Лариса Ратич','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконують Марія Стоянова та Поліна Глухенко.','Дні такі чудові ми чекали,
