INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232457','Ой на Яна на Янонька не палена Собітонька','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Вогонь-Вода. Два Голубці. Помічення-Вибір Пари. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. А на тій Вербі Рожеві Квіти. Буде тобі Квітка Красна. Івана Купала тай в Воду упала. Гоці-гоці на Потоці Два Голубці Воду пили. Тай зачали говорити кого мают з ким злучити. Три Гискри впало Три Морі стало. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Щедрий Вечер, 13-14 січня. Маланки-Василь. Коза. Про Свято Івана Купала Стежки до листків про Українські традиції. Громадська організація "Арт Екзистенція", Українська експериментальна лабораторія фольклору, Мистецьке агентство "Арт Велес" та Українсько-британське спільне підприємство "Комора" презентують проект "МОЯ УКРАЇНА. БЕРВИ", основна мета якого - показати багатства народної творчості українців. Народна культура та мистецтво українців справедливо вважаються одними з найбагатших надбань культурної скарбниці європейських націй. Проти фольклору боролася церква, його забороняли імперські та радянські укази намагаючись спотворити його сутність банальним псевдофольклором, але фольклор з його глибинною пам''яттю в кілька тисячоліть виявився надзвичайно життєздатним. Схоже на те, що фольклорну традицію може перемогти тільки Час, наступ нової цивілізації. Ми, мабуть, останнє покоління, якому надана можливість зафіксувати кращі зразки традиційної культури, зберегти їх для нащадків, адже живих носіїв автентичного фольклору стає все менше. Протягом ХХ ст. фахівцям-ентузіастам вдалося записати тисячі народних пісень, награвань, творів усної народної творчості, що зберігаються в архівах відповідних державних інституцій. Сьогодні ми ризикуємо втратити цей неоціненний скарб: велика частина унікальних фоноархівів самознищується внаслідок осипання магнітних плівок під дією часу. ("Моя Україна" - автентична музика на СD - http://media.topping.com.ua/printnews/90851.html)','Ой на Яна на Янонька не палена Собітонька
Не палена і не буде док святий Ян не приїде
Як святий Ян приїхавши Собітоньку розпалявши
Тоді будем говорити кого маєм з ким злучити

Гоці-гоці на Потоці Два Голубці Воду пили
Пили-пили скамутили і на Іншу полетіли
Сіли собі на Явора тай зачали говорити
Тай зачали говорити кого мают з ким злучити

А в Барана Гарний Петрусь а в Пелеха Красна Євця
Треба би їх получити і на Глога положити
Як на Глога так на люде шо май бути то най буде!','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_232457'), datetime('now')),datetime('now'));
