INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2323563','Вже би’м була їхала, вже би’м була йшла','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1941',NULL,'Уснословесний жанр весільна пісня, ладканка, приспівка Місце побутування с. Боберка, Боберківська сільрада, Турківський район, Львівська область Респонденти Бутрий (Бабич) Катерина Луківна, 1941 р.н., Бутрий (Маричканич) Марія Миколаївна, 1985 р.н., Бутрий Оксана Яківна, 1970 р.н. Збирачі Довгалюк Ірина, Вовчак Андрій','Вже би''м була їхала, вже би''м була йшла,
Ще''м свой мамі не вклонилася.
Кланяюсь тобі, мамо, що збудила мене рано,       |
Більш не будеш, не будеш.                        | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще''м своєму татові не вклонилася.
Кланяюсь тобі, тату, що построїв мені хату,      |
Більш не будеш, не будеш.                        | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще своїй сестриці не вклонилася.
Кланяюсь тобі, сестро, що''з навчила косу плести, |
Більш не будеш, не будеш.                        | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще''м своєму братові не вклонилася.
Кланяюсь тобі, брате, що''з наводив хлопців хату, |
Більш не будеш, не будеш.                        | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще''м своїм порогам не вклонилася.
Кланяюсь вам, пороги, де стояли білі ноги,       |
Більш не будуть, не будуть.                      | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще''м своїм воротам не вклонилася.
Кланяюсь вам, ворота, де стояла хлопців рота,    |
Більш не будуть, не будуть.                      | (2)

Вже би''м була їхала, вже би''м була йшла,
Ще''м своїм сусідам не вклонилася.
Кланяюсь вам, сусіди, що були за дня бесіди,     |
Більш не будуть, не будуть.                      | (2)','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2323563'), datetime('now')),datetime('now'));
