INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2326624','Я нап''юсь вина','Музика: Марина Тимофійчук Слова: Марина Тимофійчук. Виконує: Марина Тимофійчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли ти обіймаєш,
Здається, виростає небо...
І я відчуваю себе
Маленькою беззахисною квіткою...
Коли я стаю квіткою,
Безборонною квіткою
І заплющую очі, і лечу
Вище неба блакитного...
Не боюся ні вітру я,
Ні безумного світу не боюсь!
Коли ти обіймаєш, здається,
Я до тебе приростаю!..

Приспів:
Я нап''юсь вина,
Як закінчиться війна!
Як закінчиться війна -
Я нап''юсь тобою!
Я живу тобою, знай!
Як закінчиться війна,
Як закінчиться війна -
Я нап''юсь твоєю любов''ю!
Я нап''юсь твоєю любов''ю!

Коли ти торкаєшся
Гарячими губами до чола,
Серце гримає, гримає в груди,
Аби я його почула.
Дрібно серденько гримає
В твою руку нестриману,
Тільки не відпусти мене,
Не впусти!..
Якщо падати з неба -
То тільки, тільки
В обійми до тебе
Падати буду немов стріла!
Тільки б ти торкнувся
Гарячими губами до чола!..

Приспів.

Як закінчиться війна!    |
Як закінчиться війна!    |
Як закінчиться війна!    |
Я нап''юсь твоєю любов''ю! | (2)

Я нап''юсь тобою!..','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2326624'), datetime('now')),datetime('now'));
