INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_232563','Пливи Вінок за Водою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Вінок-Вода. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Пускання Вінків, обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Пливе Доля за Тобою. Були Світилки Яснії Зірки. Листки з приводу цієї Пісні: Українські релігійні роздуми про Бога. Еротичні містерії, тиждень від Катерини 7.12 до Калети — Передріздвяний Святочний час. Бог і Доля. Колядки про Долю. Про Свято Івана Купала Стежки до листків про Українські традиції.','Пливи Вінок за Водою
Пливе Доля за Тобою
Пливи Вінок к Бережечку
