INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328293','Ми - українські партизани','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Уснословесний жанр повстанська пісня Місце побутування смт Запитів, Кам''янка-Бузький район, Львівська область Респондент Максимишин Марія Олексіївна, 1930 р.н. Збирачі Вовчак Андрій, Мартиник Соломія','Ми - українські партизани -
Нащадки славних козаків -
Щоб нарід визволить з кайданів,
Ми б''єм проклятих ворогів.

Лунають сурми - близько воля!
Вже рветься серце, кличе кров,
В огні кується наша доля,
Встають заковані з оков.

Ми - українські партизани -
Не знаєм, шо таке є страх.
Родина наша - вирізана,
А хата - в лісі, у ярах.

Ми - українські партизани -
Рушаєм лавами у бій!
За нашим прикладом повстане
Народ пробуджений як стій!','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2328293'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2328293','Ми - українські партизани','Ми - українські партизани -
