INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328420','На купині під осокою','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1930',NULL,'Уснословесний жанр стрілецька пісня Місце побутування смт Запитів, Кам''янка-Бузький район, Львівська область Респондент Максимишин Марія Олексіївна, 1930 р.н. Збирачі Вовчак Андрій, Мартиник Соломія','На купині під осокою
Там один стрілець вмирав,
Він держав за грудь рукою -
З рани кров він зупиняв...

І потекла та кров червона,
І стікає в купину -
Там один стрілець вмирає
За ідею, за свою...

"Ой, ви друзі, мої друзі,
Я вже з вами не буду!
За свій нарід, за край рідний
Я життя своє даю".

Підняв очі, глянув вгору:
Тече кровця із грудей -
"Я вмираю, не побачу
Самостійної доби.

Я вір''ю в те, що нарід встане -
Всі завзято в бій підуть,
І тоді катам за все відплатять,
І мене там спом''януть".','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2328420'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2328420','На купині під осокою','На купині під осокою
