INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328596','Карпатські квіти','Музика: Микола Мозговий Слова: Микола Мозговий. Виконує: Luiku (Луйку)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Спалахнули сяйвом роси,
Сколихнув зорю.
Заплету тобі я в коси
Я любов свою!
Скільки літ у парі бути -
Не питай мене,
Доки ми кохаєм квіти,
Щастя не мине!

Приспів:
Ой-йой-йой-йой,
Карпатські квіти,
Розмаїстий світ,
Для кохання жити
Вам призначив літ!
Ясне сонце вкрило
Вас у кольори!
І любов на крилах
Всім даєте ви!

Ой, кохана, цими днями
Я сватів пришлю.
Зацілую до нестями,
Бо я так люблю
Твої вуста, твої брова,
Твого серця спів,
І очей ясна розмова -
Чути все без слів!

Приспів. (2)','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2328596'), datetime('now')),datetime('now'));
