INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2330354','Зимові місяці','Музика: Анатолій Салогуб Слова: Анатолій Салогуб','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Вже від снігу забіліла матінка земля,
Заметілі, хуртовини принесла зима,
Скоро прийдуть новорічні та різдвяні дні,
Заспіваємо святкові радісні пісні.

Приспів:
Весело, весело пісню заспіваємо!
Зимоньку, зимоньку дружно привітаємо!
Грудень, січень, лютий - вже до нас ідуть,
Мить щасливу й радісну хай несуть!

Місяць грудень проводжає довгий рік старий,
Місяць січень подарує людям рік новий,
Місяць лютий нам поверне чарівну весну,
Він віддасть нашу красуню зиму чарівну.

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2330354'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2330354','Зимові місяці','Вже від снігу забіліла матінка земля,
