INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328498','Добре тому коса косить','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Добре тому коса косить, кому мила їсти носить,
І моя би так косила, кіби мила приносила.
Добре тому легіньови, што ся женить при вутцьови,
А ци тому якось буде, як го женять чужі люди, гей!

Добре тому коса косить, кому мила їсти носить,
І моя би так косила, кіби мила приносила!

Гей добре ся добре маю, що на горі хижу маю,
Хижу маю на горбочку, серед села - фраїрочку,
Хижу маю смерекову, а у селі - чорноброву,
Кучерики на нюй скачуть, мої очка за ньов плачуть гей!

Добре тому коса косить, кому мила їсти носить,
І моя би так косила, кіби мила приносила!
Добре тому легіньови, што ся женить при вутцьови,
А ци тому якось буде, як го женять чужі люди.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2328498'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2328498','Добре тому коса косить','Добре тому коса косить, кому мила їсти носить,
