INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2328512','Чорна гора неорана','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Чорна гора неорана,         | (2)
Лем кулями постріляна.      | (2)

