INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2326920','Перше вересня','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Той осінній перший день
Всіх збирає школярів,
Тут не бути без пісень,
Без вітань для вчителів.
Радості немає меж
Після довгих тих розлук
І батьки щасливі теж,
Бо ведуть нас до наук.

Приспів:
Перше вересня! Про розваги забувай!
Перше вересня! Наша "воле", прощавай...
Перше вересня! - В школі двері відчиняй!
Перше вересня! - До навчання приступай!

Будуть дні науки йти,
Буде радість, буде сум,
Лиш би потім зберегти
Цих років щасливий шум.
А сьогодні щирі всі,
Знов звучить шкільний дзвінок -
При осінній тій красі
Кличе всіх нас на урок.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2326920'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2326920','Перше вересня','Той осінній перший день
Всіх збирає школярів,
Тут не бути без пісень,
Без вітань для вчителів.
Радості немає меж
Після довгих тих розлук
І батьки щасливі теж,
Бо ведуть нас до наук.

Приспів:
Перше вересня! Про розваги забувай!
Перше вересня! Наша "воле", прощавай...
Перше вересня! - В школі двері відчиняй!
Перше вересня! - До навчання приступай!

Будуть дні науки йти,
Буде радість, буде сум,
Лиш би потім зберегти
Цих років щасливий шум.
А сьогодні щирі всі,
Знов звучить шкільний дзвінок -
При осінній тій красі
Кличе всіх нас на урок.

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233073','Бог ся раждає по світу цілому','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1991','Багатотиражка Дрогобиччини "Галицька зоря" за 5 січня 1991 року.','Колядка народилася на Тернопільщині в повоєнні роки, її любили співати вояки УПА. Колядку співають на мелодію Бог ся рождає, хто ж Го може знати!','Бог ся раждає по світу цілому,
Лиш Україна в жалобі сумному.

Скрізь арешти і тюрма,
Муки і катування,
Кров українських синів
Злита слізьми матерів.
І, мов цвіт скошений в''яне,
Українська молодь гине
В тюрмах, муках і на чужині.

Рождество Христове в жалобі сумує
Господарям чесним новину віщує:

Недалеко вже той час,
Бо вже воля кличе нас,
Встань, народе, пробудись,
Скинь кайдани, озовись.
Кров братів кличе до мести,
Щоб на багнетах принести
Щастя Украйні і визволення.

Не журися, батьку і старенька мати,
Син пішов в повстанці волю здобувати.

Недалеко вже той час,
Бо вже воля кличе нас,
Встань, народе, пробудись,
Скинь кайдани, озовись.
Кров братів кличе до мести,
Щоб на багнетах принести
Щастя Украйні і визволення.','["pisni.org.ua", "cat:christian", "cat:halycki", "cat:istorychni", "cat:kolyadky", "cat:nostalgia", "cat:povstanski", "cat:suspilno-politychni", "Пісні на християнську тематику", "Пісні з Галичини", "Історичні пісні", "Колядки", "Пісні з ностальгічними мотивами", "Повстанські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233073'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_233073','Бог ся раждає по світу цілому','Бог ся раждає по світу цілому,
