INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2329158','Ой, горілко біла, біла','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1958',NULL,'Уснословесний жанр родинно-побутова пісня Місце побутування с. Боберка, Боберківська сільрада, Турківський район, Львівська область Респонденти Возняк Ганна Луківна, 1958 р.н., Гошко Люся Ільківна, 1941 р.н., Проньо Василь Дмитрович, 1970 р.н. Збирачі Іванищук Марія, Беднарська Ружена','Ой, горілко біла, біла,       | (3) |
Я би тебе ложков їла.               | (2)

Я за тебе - три рублі,       | (3) |
А ти мине - до зимлі.              | (2)

Я за тебе - п''ятака,         | (3) |
А ти мене - цапака.                | (2)

Я за тебе - срібло-злото,    | (3) |
А ти мене - у болото.              | (2)

Я за тебе, як за пані,       | (3) |
А ти мене - в колобані.            | (2)

Ідуть люди, питаються,       | (3) |
Шо за пані купаються.              | (2)

А я собі така пані,          | (3) |
Купаюся в колобані.                | (2)

В колобані - буль-буль-буль, | (3) |
А я лежу, як куркуль.              | (2)

А я пані з Самбора,          | (3) |
Купаюся, як свиня.                 | (2)

А я пані із-зі Львова,       | (3) |
Купаюся, як корова.                | (2)','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2329158'), datetime('now')),datetime('now'));
