INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331111','Хліборобська Величальна','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Заграйте, сурми, на зорі,
Возрадуйся, щаслива мати,
Твої сини-богатирі,
Виходять землю засівати.

Приспів:
Сійся, родися, зелено розвийся,
Наливайся сонцем, золоте зерно!
Жито, пшениця та всяка пашниця,
Нехай колоситься людям на добро!

Благословенна борозна
Дощами теплими омита,
О, земле, сонячна моя,
Єднайся колосом і цвітом.

Приспів.

Довіку земле молодій,
На радість нам і нашим дітям,
Хвала людині трудовій,
Хвала рукам, що пахнуть хлібом.

Приспів.','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2331111'), datetime('now')),datetime('now'));
