INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331797','Кую-кую чобіток','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1936','аудіозапис','Місце побутування с. Боберка, Боберківська сільрада, Турківський район, Львівська область Респондент Погулич Феня Дмитрівна, 1936 р.н. Збирачі Винницька Ліля, Кльок Юлія','Кую-кую чобіток,
Подай бабі молоток,
Ни подаш молоток -
Ни підкую чоботок!

Кую-кую чобіток,
Подай бабі молоток,
