INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2330379','Емігрантка','Музика: Володимир Сірий Слова: Олексій Тичко. Виконує: Володимир Сірий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Твоя пора настала року,
Ще любиш осінь, чи вже ні,
У мегаполісі Нью-Йорку,
Від України вдалині?..

Приспів:
На вітрі айстри б''ють поклони,
Бушує море, океан...
В калюжі жовте листя тоне,
Я тут, а ти - далеко там...

Чи каву п''єш у ліжку зранку,
Чи кольорові твої сни?..
Як там живеться, емігрантко,
Зимою, влітку, восени?..

Приспів.

Прийшла неждано осінь знову -
І над Гудзоном, і Дніпром
Малює дощ туманну долю,
Глибоку лінію долонь...

Приспів.

В калюжі жовте листя тоне,
Я тут, а ти - далеко там...','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2330379'), datetime('now')),datetime('now'));
