INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233226','Листопад *','(Листопад 200 ****). Музика: Гайдамаки Слова: Олександр Ярмола. Виконує: Гайдамаки','uk','ukraine_1991',NULL,'2005','http://www.haydamaky.com/','Виконують Гайдамаки (альбом "Перверзія" 2005 р.)','Поети складають пісні, не гаючи часу свого на землі.
Системи працюють, їх пильнують, купляють, засуджують, лікують.
Свідомість їх не потрібна нікому й кохання приречене в світі тварин,
З якого постала Людина, на неї ти так не дивися, вона ще дитина!

Прийшов листопад і раптом ти зрозумів, що не маєш снів
З тих пір, як твоя крів отруєна ядом стріл.
Щоночі тіло твоє вмирає, душа тікає й проникає
За стіни багатоквартирних домів, у шоці від того, що діється з нами...

І знов забуває, куди вертає, фізичне тіло собі шукає
У світі тварин, потоці машин, поганих пісень, сумних очей,
Картин, від яких псується крів. А може, це просто прийшов листопад,
А ти ще не звик до природніх змін? А може, тебе вже нема?

Не треба спішити жити, раптом прокинутися й зрозуміти
Усе, що ся діє навколо, побачити в новому цвіті
Стільки ясних очей, красивих людей, пісень, що гукають жити
Наших дітей у майбутній день, обняти й благословити!..

Поети складають пісні, не гаючи часу свого на землі.
Системи працюють, їх пильнують, купляють, засуджують, лікують.
Вони замовкають, поволі зникають, пісні забуваються, люди лишаються
В стінах багатоквартирних домів, з яких вже ніколи на Світ не вертаються!','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233226'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_233226','Листопад *','Поети складають пісні, не гаючи часу свого на землі.
Системи працюють, їх пильнують, купляють, засуджують, лікують.
Свідомість їх не потрібна нікому й кохання приречене в світі тварин,
З якого постала Людина, на неї ти так не дивися, вона ще дитина!

Прийшов листопад і раптом ти зрозумів, що не маєш снів
З тих пір, як твоя крів отруєна ядом стріл.
Щоночі тіло твоє вмирає, душа тікає й проникає
За стіни багатоквартирних домів, у шоці від того, що діється з нами...

І знов забуває, куди вертає, фізичне тіло собі шукає
У світі тварин, потоці машин, поганих пісень, сумних очей,
Картин, від яких псується крів. А може, це просто прийшов листопад,
А ти ще не звик до природніх змін? А може, тебе вже нема?

Не треба спішити жити, раптом прокинутися й зрозуміти
Усе, що ся діє навколо, побачити в новому цвіті
Стільки ясних очей, красивих людей, пісень, що гукають жити
Наших дітей у майбутній день, обняти й благословити!..

Поети складають пісні, не гаючи часу свого на землі.
Системи працюють, їх пильнують, купляють, засуджують, лікують.
Вони замовкають, поволі зникають, пісні забуваються, люди лишаються
В стінах багатоквартирних домів, з яких вже ніколи на Світ не вертаються!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2331665','Гей, ой, по морю','Українська народна пісня','uk','ukraine_before_1917',NULL,'1878','аудіозапис','Мелодія з записів Максима Коросташа, 1927 р., Черкаська обл., Шполянський р-н, с.Лип''янка (№86, записано від Бородаївни). Текст походить з с.Богодар кол. Олександрівського повіту, підібраний за виданням: Д.И.Эварницкий, Малороссийские народные песни, собранные в 1878–1905 гг., Екатеринослав, 1906. – C.681-683.','Гей, ой по морю,
Ой по морю по синьому,
По каменю по білому.

Гей, сокіл з орлом,
Сокіл з орлом купається,
Сокіл орла питається.

Гей, чи був, орле,
Чи був, орле, за Дунаєм?
Чи не знаєш про ногаїв?

Гей, ішли ляхи,
Ішли ляхи на три шляхи,
А татари на чотири.

Гей, запорожці
Запорожці поле вкрили.
Шабельками заяснили.

Гей, попереду,
Попереду гетьман іде,
За собою військо веде.

Гей, в правій руці
В правій руці держить меча,
В лівій руці горить свіча.

Гей, горить свічка,
Горить свічка восковая,
Тече річка кровавая.

Гей, над річкою,
Над річкою ворон кряче,
По синові мати плаче.','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2331665'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2331665','Гей, ой, по морю','Гей, ой по морю,
Ой по морю по синьому,
По каменю по білому.

Гей, сокіл з орлом,
Сокіл з орлом купається,
Сокіл орла питається.

Гей, чи був, орле,
Чи був, орле, за Дунаєм?
Чи не знаєш про ногаїв?

Гей, ішли ляхи,
Ішли ляхи на три шляхи,
А татари на чотири.

Гей, запорожці
Запорожці поле вкрили.
Шабельками заяснили.

Гей, попереду,
Попереду гетьман іде,
За собою військо веде.

Гей, в правій руці
В правій руці держить меча,
В лівій руці горить свіча.

Гей, горить свічка,
Горить свічка восковая,
Тече річка кровавая.

Гей, над річкою,
Над річкою ворон кряче,
По синові мати плаче.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23318','Ой там на горі','Українська народна пісня. Виконує: Тріо Мареничів','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Ой там на горі, ой там на крутій,
Ой там сиділи пара голубів.       | (2)

Вони сиділи, цілувалися,
Сивими крильми обнімалися.        | (2)

