INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2332919','Футбол!','Музика: Віталій Кобринович Слова: Віталій Кобринович. Виконує: Гурт МалДіви','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ось пролунав свисток,
Суддя команду дав гру розпочати
І вже забитий стадіон,
Усі прийшли уболівати!
Улюблена команда наша
Просто зараз атакує,
Ще мить - зірветься стадіон,
І ми всі разом проскандуєм:
Треба гол!

Приспів:
Давай! Давай! Давай, забивай!
Ти - чемпіон! Нам треба гол!
Давай! Давай! Давай, забивай!
Ти - чемпіон! Всім треба гол!
Гол! Гол! Гол! Гол! Гол!

Принишкли вболівальники
Й усі в очікуванні голу,
Ми подаємо кутовий -
Заб''ємо ще обов''язково!
Давай, покажем вищий клас -
Команда наша атакує!
Ми всі підтримуємо вас,
Давайте разом проскандуєм:
Треба гол!

Приспів. (2)','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2332919'), datetime('now')),datetime('now'));
