INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2332869','Перший дзвоник','Слова: Олена Заблоцька','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Діана Вязовченко.','Ось і вересень прийшов,
Ми йдемо до школи,
Все таке нове для нас,
Різнокольорове!
Нові друзі, вчителі,
Ноти, цифри, букварі,
Світ цікавий кличе нас
На шкільний дзвіночок!

Приспів:
Перший дзвоник
Пісню співає для нас!
Перша вчителька
Нас зустрічає!
В цей святковий день
Я йду в перший клас!
Світ пригод
Школярів чекає!

Перше вересня настало -
Я збираюсь в школу!
У душі моїй лунає
Пісенька чудова,
Ранець свій збираю я
В новий день, нове життя!
Ну ж бо двері відчиняй,
Моя рідна школо!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2332869'), datetime('now')),datetime('now'));
