INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333515','Миколай','Музика: Анна Кривута Слова: Анна Кривута. Виконує: Подих весни','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'До святкової кімнати
Вже заходить Бородатий,
Щось під подушку сховає,
Покладе і вмить щезає.
І не мама, і не тато
Нам придумали це свято.
Подарунки точно знаю:
Від Святого Миколая!

Приспів:
Миколай! Миколай! Миколай!    |
Ти до мене, чемної, поспішай! |
Ти мене слухняною привітай,   |
Миколаю! Миколай!             | (2)

Принесе в мішку гостинці
І солодощі у скриньці,
Чи новенькі черевички,
Або теплі рукавички!
А комусь красуню Барбі,
Або кольорові фарби,
Повну іграшок валізку,
А комусь тоненьку різку! Ой!

Приспів.

Я бажання написала
Та під подушку поклала.
Прийди, Святий Миколаю,
Цілий рік Тебе чекаю!
Та, напевно, я заснула,
Як прийшов Він не почула,
А коли я вранці встала -
Подарунки відшукала!

Приспів.

Миколай! Миколай! Миколай!
Ти до неї, чемної, поспішай!
Ти її слухняною привітай,
Миколаю! Миколай!
Миколаю! Миколаю! Миколай!','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333515'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2333515','Миколай','До святкової кімнати
