INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333828','Іде Новий Рік!','Музика: Сергій Родько Слова: Алла Бінцаровська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Іде білий сніг,
Чарує іскринками,
Ми знову милуємось
Диво-сніжинками -
Це зима!
В чарівнім танку
Хурделиця крутиться,
У Році Новому ми вірим:
Все збудеться! -
Це зима!

Іде Новий Рік! -
Він буде кращим, як торік!

