INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333212','Мамина молитва','Музика: Тетяна Піскарьова Слова: Тетяна Піскарьова. Виконує: Тетяна Піскарьова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як же я молилася, дитино моя,
Сину єдиний, бажаний,
Щоб була щасливою доля твоя,
Щоб ти горе не зустрів так рано!..
Ну, а ти зустрів війну -
Подививсь їй в очі,
І тепер я не засну,
Не засну я до півночі,
Буду я молитися, просити Бога,    |
Щоб вернув тебе живого!           | (2)

Мамина молитва
В світі найсильніша!
Молить мама Бога,
Щоб він сина не залишив!
Миру Україні, спокою і тиші!
Молить мама Бога,                 |
Щоб він сина не залишив!          | (2)

Що ж тобі сказати,
Коли в наступ ідеш
Коли міцно тримаєш ти зброю -
Це твоя земля і кращої не знайдеш,
Ти - мій син і правда за тобою!
Побажаю я тобі слави, сили й волі,
України ви сини - Ви тепер герої!
Мами Богу моляться, молитва лине, |
Щоб вернулися живими!             | (2)

Мамина молитва
В світі найсильніша!
Молять мами Бога,
Щоб дітей їх залишив!
Миру Україні, спокою і тиші!
Молять мами Бога,                 |
Щоб дітей їх не залишив!          | (2)

Мамина молитва
В світі найсильніша!
Молять мами Бога,
Щоб дітей їх залишив!
Миру Україні, спокою і тиші!
Молять мами Бога,                 |
Щоб дітей їх не залишив!          | (2)','["pisni.org.ua", "cat:ato", "cat:pro-ditey", "Пісні російсько-української війни та АТО", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333212'), datetime('now')),datetime('now'));
