INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233515','Що в Батька Грицька тай Син Василько','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Буду в січі жить Бога боронить — ця обітниця має на увазі мітичну чи історичну Січ? А може також: і в січі світу не по Правді, ― яка б вона не була, ― буду жити, Бога боронити! І оженюсь! ― І буде Син і буде Мати і будуть Люди на Землі:-) Буде в Тебе Господь на Вечері. Ой там виxодило та Три Товариші. Буде Тобі Три Дорозі. Буду в січі жить Бога боронить. Що в Батька Грицька тай Син Василько Хто ж нас поцілує в уста малинові. Чого Старий не женишся. Листки з приводу цієї Пісні: Ідея Бога на Свят-Вечер. День реліґійно-філософських роздумів на Астральні теми, Варвари 17.12. Українські релігійні роздуми про Бога. Традиції самогуртування: Cвятий Збір. Вістуни великого Свята, аскети, люди ідеї. Вилинули Соколи с Чужої Сторони: Алегорія неволі сокола. Рокове Коло. Стежки до листків про Українські традиції. Символіка Щедрого Вечера і Василя. Щедрий Вечер зачинається властиво під Новий Рік, 13-14 січня (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда)... Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Що в Батька Грицька тай Син Василько

Приспів:
Грай Море грай !

Молодий Василько тай на Конику
А що в Василька Коник Вороний
Коник Вороний Жупан Червоний
Срібне Сідельце Золоте Стременце
Шапка Чорная Шабля Гострая

Він сів на Коня виїхав з Двора
Шапочку ізняв всім поклонився
Всім послав привіт ждіть через П''ять Літ
Буду в січі жить Бога боронить
А як повернусь може оженюсь
А як повернусь тоді оженюсь','["pisni.org.ua", "cat:manrivni", "cat:shchedrivky", "cat:vesilni", "Пісні на мандрівну тематику", "Щедрівки", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233515'), datetime('now')),datetime('now'));
