INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333818','Різдвяне диво','Музика: Сергій Родько Слова: Алла Бінцаровська. Виконує: Гурт Струни Серця','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В сяйві зір кришталевому, ніжному,
Поспішаючи в кожну оселю,
Принесе на крилі білосніжному
Добру казку різдвяний ангелик!
Світ засяє вогнями барвистими -
Це земля зустрічає Різдво,
Це стежиною світлою чистою
Йде велике святе торжество!

Приспів:
Нехай Різдвяне диво
Дарує мить щасливу
І серце щиру радість
Віднайде!
І, як у добрій казці,
Незнане тихе щастя
У кожен дім
Назавжди увійде!

За святковим столом зустрічається
Знову вся українська родина! -
Хай бажання і мрії збуваються
В день народження Божого Сина!
І, озвавшись різдвяною згадкою,
У душі залишаючи слід,
Лине пісня дзвінкою колядкою
І підспівує нам цілий світ!

Приспів. (2)

І, як у добрій казці,
Незнане тихе щастя
У кожен дім
Назавжди увійде!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333818'), datetime('now')),datetime('now'));
