INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2335158','Добрим будь!','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дощ умив усе довкола,
Полив квіти голубі,
Не жалій добра ніколи,
Все повернеться тобі!

Приспів:
Добрим будь! Добрим будь!
Вирушай з добром у путь!
Добрим будь! Добрим будь!
Посміхнутись не забудь!

А веселка кольорова
Засвітилась в небесах,
Не жалій добра ніколи,
Все повернеться в житті!

Приспів.

Не кажи лихого слова
І слабкого захисти!
Не жалій добра ніколи,
Все повернеться в житті!

Приспів.','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2335158'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2335158','Добрим будь!','Дощ умив усе довкола,
