INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2333767','Біло-біло навкруги',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Біло-біло все навкруг,
Засинає ліс і луг,
І радіє вся земля,
Що прийшла зими пора!
Весело тепер усім,
Скоро свято прийде в дім!
Ми зустрінем Новий рік,
Що несе нам радість й сміх!

Приспів:
Зимонька вітає нас,          |
Їй радіє весь наш клас!      |
Тільки вийдеш на поріг -     |
Скрізь іскриться білий сніг! | (2)

Закружляєм у танку,
Втнемо пісню гомінку,
Бо в цю пору повсякчас
Новорічне свято в нас!
Наступив веселий час,
Бо прийшла зима до нас,
Біло-біло-голуба
Веселунка снігова!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2333767'), datetime('now')),datetime('now'));
