INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2335267','Море','Музика: Зоя Красуляк Слова: Зоя Красуляк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Море казкове, море зелене,
Хвилі шепочуть про щось біля мене,
Я так дружити з морем люблю,
Воно нам розказує казку свою!

Приспів:
Є на морі стежка в срібному піску,
Ходить там русалка в золотім вінку,
Весело моргає місяць молодий,
Не пускає танцювати батько водяний.

Море давно подружилося з небом,
Тут сумувати нікому не треба,
Хвилі тихенько біжать на пісок,
Море розказує казку казок!

Приспів.

Море казкове, море зелене,
Хвилі шепочуть про щось біля мене,
Я так дружити з морем люблю,
Воно нам розказує казку свою!

Приспів. (2)','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2335267'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2335267','Море','Море казкове, море зелене,
Хвилі шепочуть про щось біля мене,
