INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_233675_l1','pisniua_233675','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2335410','Найкращі в світі','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хто сказав, що наші мами
Серцем постаріли?
Хто сказав, що наші мами
Зовсім зажурились?
Оберніться, подивіться,
Ніде правди діти:
Наші мами, наші мами,
Як в садочку квіти!

Хай лунає пісня ця між нами! |
Хай всі знають -             |
В нас найкращі в світі мами! | (2)

Час летить, і непомітно
Діти виростають.
Час летить, і пташенята
Крила підіймають.
Очі мами слід за вами
Долами й стежками,
Буде завжди поряд з вами
Рідне серце мами!

Хай лунає пісня ця по світу! |
Хай всі знають -             |
В нас найкращі в світі діти! | (2)

Речитатив:
Любі наші неньки,
Ви найкращі в світі!
Хай для вас, рідненькі,
З неба сонце світить!
Хай надія й віра оживає знову!
Ми бажаєм щиро радості й любові!

Хай лунає пісня ця між нами!
Хай всі знають -
В нас найкращі в світі мами!
Хай лунає пісня ця по світу!
Хай всі знають -
В нас найкращі в світі діти!','["pisni.org.ua", "cat:dytyachi", "cat:pro-batkiv", "cat:pro-ditey", "Дитячі пісні", "Пісні про любов до батьків", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2335410'), datetime('now')),datetime('now'));
