INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2336212','Нашим Героям','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Обірвалося життя, обірвалося умить -
Вже душа у небо летить...
Молоді і повні сил полягали до могил
Замість того, щоб далі жить...

Приспів:
Вони прилетять
Ангелами з небес...
Вони прилетять,
Щоб захистити нас...
А ми ніколи не забудем
Тих кривавих днів,
України втрачених синів!..
А ми ніколи не забудем
Тих гірких смертей,
України втрачених дітей!..

Вибрав Бог саме їх з-поміж інших усіх
І забрав в обійми свої...
Полягти у бою за вітчизну свою -
Це найбільша честь на землі!..

Приспів.

Щоб не марно пролилась
Молода їхня кров, -
Об''єднаймо наші серця!
Через гнів, через страх,
Через біль у очах
Треба далі йти до кінця!

Приспів.','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2336212'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2336212','Нашим Героям','Обірвалося життя, обірвалося умить -
