INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2335457','Новий Рік','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Стукоче в вікна грудень,
І знову зимно буде,
І падає лапатий білий сніг.
Іде на радість людям,
На радість добрим людям,
Казковий довгожданний
Новий рік!

Приспів:
Новий Рік!
Кружляє білий сніг усюди!
Новий Рік ступає на поріг!
Новий Рік!
Нехай усі здорові будуть!
Щастя всім
В казковий Новий рік!

Нехай у вашій хаті завжди панує свято
Із посмішок і радісних розмов!
Щоб не було печалі, щоб лихо обминало,
Хай будуть з вами щастя і любов!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2335457'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2335457','Новий Рік','Стукоче в вікна грудень,
І знову зимно буде,
І падає лапатий білий сніг.
Іде на радість людям,
На радість добрим людям,
Казковий довгожданний
Новий рік!

Приспів:
Новий Рік!
Кружляє білий сніг усюди!
Новий Рік ступає на поріг!
Новий Рік!
Нехай усі здорові будуть!
Щастя всім
В казковий Новий рік!

Нехай у вашій хаті завжди панує свято
Із посмішок і радісних розмов!
Щоб не було печалі, щоб лихо обминало,
Хай будуть з вами щастя і любов!

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2335457_l1','pisniua_2335457','YouTube','https://www.youtube.com/watch?v=kiexiyvCJ8g','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23379','Стомлене місто вже спить','Музика: Ігор Особік Слова: Ігор Особік','uk','ukraine_1991',NULL,NULL,'Збірник пісень Студентського братства Львівської політехніки.- Львів, 2000','* Тут акорд F у 1-му рядку береться у всіх куплетах, крім 1-го.','Am                                F*      Am
Стомлене місто вже спить і таємничо мовчить,
Лише підмругують в тьмі ліхтарі.
Я по бруківці іду, свої печалі несу,
Холєра ясна, самотньо мені.

То вже не раз і не два, втікаю з хати - дарма.
Від себе, певно, ніде не втечеш.
Моя княгине ночі, ти знов прийшла уві сні,
Чому так довго ти мучиш мене?

Приспів:
Де вже ти є, доле моя?
Давно тебе шукаю я,
Доле моя,
Доле моя кохана.
Доле моя кохана.

Мене бентежить твій жест - піднятий догори перст,
Неначе світло до мене вночі.
Кличеш мене за собов. Таки своє - про любов,
А я в трусах, і незручно мені.

Я простирадлом, як грек, обидві руки вперед,
Кажу "Я йду вже, княгине, я йду".
Я - обнімати тебе, ти - цілувати мене,
І в цей момент я чолом об стіну.

Приспів.

І вже заснути ніяк. Кручуся так або сяк,
Перед очима бринить силует.
За олівець і папір, але не можу, ні-ні,
Я зобразити ніяк твій портрет.

Знайомий мій психіятр сказав: "Ти просто вар''ят.
Тобі потрібно дівчину просту".
І ось іду я сумний, зденервований такий,
І більше кави я на ніч не п''ю.

Приспів.

Птахи вже не гомонять, напевно міцно вже сплять,
Щоб зранку знов милувати аш слух.
А я звіздаю собі тихенько так: "...".
Княгине ночі, тебе я знайду.

Приспів.','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23379'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23379','Стомлене місто вже спить','Am                                F*      Am
Стомлене місто вже спить і таємничо мовчить,
Лише підмругують в тьмі ліхтарі.
Я по бруківці іду, свої печалі несу,
Холєра ясна, самотньо мені.

То вже не раз і не два, втікаю з хати - дарма.
Від себе, певно, ніде не втечеш.
Моя княгине ночі, ти знов прийшла уві сні,
Чому так довго ти мучиш мене?

Приспів:
Де вже ти є, доле моя?
Давно тебе шукаю я,
Доле моя,
Доле моя кохана.
Доле моя кохана.

Мене бентежить твій жест - піднятий догори перст,
Неначе світло до мене вночі.
Кличеш мене за собов. Таки своє - про любов,
А я в трусах, і незручно мені.

Я простирадлом, як грек, обидві руки вперед,
Кажу "Я йду вже, княгине, я йду".
Я - обнімати тебе, ти - цілувати мене,
І в цей момент я чолом об стіну.

Приспів.

І вже заснути ніяк. Кручуся так або сяк,
Перед очима бринить силует.
За олівець і папір, але не можу, ні-ні,
Я зобразити ніяк твій портрет.

Знайомий мій психіятр сказав: "Ти просто вар''ят.
Тобі потрібно дівчину просту".
І ось іду я сумний, зденервований такий,
І більше кави я на ніч не п''ю.

Приспів.

Птахи вже не гомонять, напевно міцно вже сплять,
Щоб зранку знов милувати аш слух.
А я звіздаю собі тихенько так: "...".
Княгине ночі, тебе я знайду.

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2338777','Я трояндою стану','Слова: Володимир Дашавський','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Я трояндою білою стану
Мене ти в руки візьмеш,
Вдихнеш аромат чарівний,
До губ своїх прикладеш.
Ця троянда, біла троянда
Як світле кохання моє,
Ця білосніжна чиста квітка
Як найщиріше бажання моє.

Трояндою червоною стану,
Її в руки  ніжно  візьмеш,
Радісна сльозинка моя впаде -
За краплину роси ти приймеш.
Троянда чарівна червона
То моя вірна та щира любов.
Ця троянда чарівна червона
То серця мого гарячая кров.

Пелюстками троянд  я стану,
І дорогу тобі щедро встелю.
По них обережно будеш ступати,
А піднімусь і з тобою разом піду.
В пелюстках цих квітів чарівних,
Найщиріші мої є там почуття.
Трояндами білими та червоними
Хай стелиться доля твоя і моя.','["pisni.org.ua", "cat:boykivski", "Пісні з Бойківщини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2338777'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2338777','Я трояндою стану','Я трояндою білою стану
