INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233910','Коляд Коляд Колядниця (2)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Хай вам Бог за ці Дари Дасть Багатії Отари: Тобто і — щедре та ясне зоряне небо! Стародавні Колядки-Щедрівки: Українські. Радуйся Земле Коляда їде! Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Коляд Коляд Колядниця
