Та бувайте всі здорові !','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_233910'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_233910','Коляд Коляд Колядниця (2)','Коляд Коляд Колядниця
