INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_233990','Радуйся Земле Коляда іде','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Духовенство з постійною службою Богу. Ідея вселюдного покликання до служби Богові. Зваживши цей незвичайно високий і вселюдний підйом реліґійний в Староукраїнськім Різдвянім святі; тую всенародну участь в многоті реліґійних містерій, цей молитвенний настрій тисяч Колядок, це загальне почуття потреби дійової жертвенности, — можна зробити висновок, що слово Коляда виражує дійовий культ і вселюдний реліґійний настрій народу, народний душевний зов до реліґійної служби Богу. Може і тому є в Українського народу в великій пошані установа Колядників, ревних служивців старого шанування. Багацтво ідей в Українськім імені Коляда. Значення Коляди як свята повинно би виходити з її імени. Походження того імени темне з лінґвістичного й етнічного огляду і лишень з його застосування при Різдвяних містеріях і обрядах можна робити здогади про його значення й етнолінґвістичну приналежність. Отже: Називають Колядою — саме Свято Різдвяне: Коляда — це друга технічна назва Різдвяного Свята. Хлібом-Колядою обдаровують Колядників-співаків, яких уважає нарід за Небесних післанців або за Святочних Духівників. Називає отже нарід Колядниками цих ідеальних своїх Духівників-піснярів, які є уособленням Старовіцьких Українських традицій і мрій про Послів Небесних, звіщаючих народові велику світову містерію, тайну Різдва Світа і появу Господа. Постаті тих Колядників зливаються в уяві народу з мітольоґічною Астральною Трійцею, що приходить в гостину до ідеального Господаря. В дивнім загально поширенім містицизмі Різдвяних Свят, який заволодів усією народною психікою, оці Духівники-Колядники стають в очах народу оповиті таємним німбом Святости, — вони самі собою приявляють Первовічні Небесні явища, тобто Астральну Трійцю. Їх називає нарід "Божими Служеньками", Трьома Небесними Товаришами, Трьома Братами, (Трьома) Королями. Вони звіщають народові давні таїнниці Світа, приходячи в гостину до Господаря несуть йому благословенство для роду і плоду і всяке добро і щастя від Господа. Колядників можуть бути більші гуртки та все між ними є три передові. Звичайно однакож гурт Колядників, виступаючи колядувати, ділиться на гуртки по три особи і так, Трійками, розходяться колядувати (принагідно "щедрувати"). Називаються Колядами або Колядками — Святоріздвяні старинні пісні, що проголошують та поширюють між народом провідні ідеї Свята Коляди, всю його містику, весь його реліґійний чар і зміст. Староукраїнські Колядки мають в першій мірі всі характер культово-реліґійний, з кількома відмінами реліґійного шанування відповідно до культурно-історичного розвитку Українського народу. Та основою цього шанування є ідея Почину Світа і його Творця. Для того всі Українські Колядки можна визначити як міти про Почин Світа і Первовічне людське життя. Тому то і традиції про первісне господарське й суспільне життя народу містяться в Колядках. Називають Колядою — Дідуха–Прадіда, що є мітольоґічною постаттю Свята. Коли вносять на Свят-Вечір сніп пшениці, або жита чи іншого збіжжя, називають цей сніп Колядою. Подано було вже пояснення, що Дідух — це символічна постать Різдва і що його звуть Різдвом для того, бо Прадід — це мітичний культурний лицар і приносець культурних дібр; а саме Різдво як Різдво Світа дає народові перші культурні здобутки: збіжжя, пашню, звірину та ін. — і через те уявляється народові доброприносцем і якоюсь ідеальною поставою. Окрім цього пояснення, є інше — має Дідух ще особливу долю зображування кожного з цих благ, які Різдво приносить, та висловлення собою всіх Святочних мотивів. Тому звуть його (іменем Різдвяного Свята) — Колядою. Називають Колядою — настільний Колач або Хліби на Святій Вечері. Тим Колачем чи тими Хлібами складає нарід свою первісну жертву Богові. Називають Колядою — Святочну жертву. Жертва величальна і подячна Творцеві Світа за його Сотворення. Ідея первісних жертв є в Українського народу здавен-давна і загально-принята. Через саме Різдвяне свято вона є поширена і знана між народом по всій Україні. Жертви первісні практикуються досі у деяких народів природи з найстаршими культурами. Первісна жертва є прототипом жертви Богові та найбільше первісною реліґійною дією. Всюди у пракультурних народів приносять лише первісні жертви і по при них ніяких інших жертв не приносять. Ознакою жертв пракультурного округа є їх віддавання Найвищому Єству з виразом почести і любови. З кожного добутку — дар Богові; це перша гадка Господаря — і нема навіть жадного застереження з його сторони про свою частку. Називають Колядою — Хліб: Хліб-Коляда має значення символу культурних первісних здобутків, виражених загально "хлібом". Святовечірній хліб називають ще Корочуном і це не тільки символ особи Прадіда, але і тих первісних культурних здобутків, які приписує нарід Прадідові. Таке саме значення символу культурних первісних здобутків, виражених загально "хлібом", має і Хліб-Коляда. Як переконаємося з опису Святої Вечері, Колач і Хліб — це суттєві її речі. Вони появляються на ній як найкращі, ідеальні, здобутки і в багатшім виді: як хліб з чаркою сирого меду на нім, пшениця з медом (Кутя), хліб печений на меді (Медівник) — звичайно в подобі великих виплітаних медівникових звізд. Це Святочне сполучення двох зразків поживи, хліба і меду, є висловом ідеалу первісного Українського рільника й пасічника разом і вважається народом Колядою вищої якості. Пшениця, мід та віск і пчоли є особливо ідеалізовані Колядками про Сотворення Світа. Називають Колядою — два або три Хліби Святочні разом, з особливою їх символікою як постави Астральної Трійці: Місяця, Сонця і Зорі, або: Місяця, Сонця і Господа, — постави Небесних Святовечірніх гостей. З оцими-то символічними Хлібами обходить Господар хату, своє подвір''я та стайні з худобою. Називають Колядою — Святовечірні Хлібні дари: одні з них призначують на пожертвування для церкви, другими обділюються взаємно з дальшою й ближчою ріднею, відносять як "Коляду" або "Вечерю" своякам, крівним, убожині, приятелям. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Радуйся Земле Коляда іде! Ой як то ще було із Нащада Світа. Коли не було з Нащада Світа Славен єс Боже по всему Сьвіту А цього Двора не минаємо Святий Вечор Ми з Колядою під Ваші Стріхи Ой Вечор Добрий Пан Господару Святий Вечор Ой Добрий Вечір Пане Господарю ми в Тебе Ой чи є чи нема Пан Господар Дома Радуйся Земле Коляда іде Чи в Дома вдома Господар дума Чи є чи нема Господар Дома Чи вдома вдома Пані Бабуня А в Нашого Дядька у Дворі Береза В Саду Садочку Вишня стояла Добрий Вечір Тобі Пане Господарю Радуйся (1) Ой грало Море в Неділю рано Ой Сивая та і Зозуленька Ой там за Горою та за Кам''яною Ходить походить Місяць по Небу Ци Ти Дома Гречний Пане Чи Дома Дома Микола Дома Пускай Старий Рік приймай Новий Рік. Віншуєм Тя Господарю Ой завіяли Буйні Вітрови Старий Рік минає Новий наступає Коляд Коляд Колядниця. А в Печі Пироги печуцця Бігла Теличка з Набережничка Бігла Теличка тай з Бережечка За вікном чорна хмара в''ється Коляд Коляд Колядниця Коляд Коляд Колядниця (2) Коляд Коляд Колядниця (3) Колядую колядую Ковбасу чую Надворі Чорна Хмара в''єцця Надворі Чорна Хмара в''єцця (2) Ой Коляда Колядниця дайте Мачку до Кутиці Пустіть до Хати колядувати Щедрик Ведрик дайте Вареник Щодрий Вечор Добрий Вечор Щодрий Вечор Добрий Вечор Василє Я Маленький Хлопчик А ми будемо всі разом Господа молити. Дякуймо Вам Файні Ґазди за Вашу Гостину Читати листки з приводу цієї Пісні: Що означає ім''я "Коляда"? Що означає "Дідух"? Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Стежки до інших листків про Українські традиції.','Радуйся Земле Коляда іде

