INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2340369','Пісня про Конотопську битву','Музика: Ігор Рачко Слова: Ігор Рачко. Виконує: Ігор Рачко','uk','ukraine_1991',NULL,'2017','Літопис авторської пісні України №18 (450) 2017 рік.',NULL,'До города Конотопа військо підступало,
Воєводи Трубецького лагерями стало.
Славний гетьман наш Іван Виговський
На ту облогу зібрав військо козацькеє
Ще й орду в підмогу.

Захотіли козаченьки москаля провчити,
І для цього задумали річку загатити.
Потаємно вдень і вночі гатку насипали,
Після цього все довкола як болото стало.

Орда зліва, а військо справа, славне з козаками,
Причаїлися, і в заплаві, на січу чекали.
Були послані загони на стан Трубецького,
Щоби заманить москаликів на слизьку дорогу.

Стала стріча, стала січа, ревнули гармати,
Скресли шаблі — козаченьки стали відступати.
Москаль реве, москаль тисне скільки має сили,
Аж допоки у болото їх не заманили.

От тоді вже, у болоті, гарно обступали,
Били, різали й рубали, в болото втоптали.
Зранку рано й до полудня гармати ревіли,
Списи гнулися й ламалися і стріли летіли.

Заробили москалики чого не бажали —
Постріляні й порубані в багнюці конали,
Слава ж батьку Івану Виговському, слава Україні!
Слава війську козацькому одвіку й до нині!','["pisni.org.ua", "cat:istorychni", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2340369'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2340369','Пісня про Конотопську битву','До города Конотопа військо підступало,
Воєводи Трубецького лагерями стало.
Славний гетьман наш Іван Виговський
На ту облогу зібрав військо козацькеє
Ще й орду в підмогу.

Захотіли козаченьки москаля провчити,
І для цього задумали річку загатити.
Потаємно вдень і вночі гатку насипали,
Після цього все довкола як болото стало.

Орда зліва, а військо справа, славне з козаками,
Причаїлися, і в заплаві, на січу чекали.
Були послані загони на стан Трубецького,
Щоби заманить москаликів на слизьку дорогу.

Стала стріча, стала січа, ревнули гармати,
Скресли шаблі — козаченьки стали відступати.
Москаль реве, москаль тисне скільки має сили,
Аж допоки у болото їх не заманили.

От тоді вже, у болоті, гарно обступали,
Били, різали й рубали, в болото втоптали.
Зранку рано й до полудня гармати ревіли,
Списи гнулися й ламалися і стріли летіли.

Заробили москалики чого не бажали —
Постріляні й порубані в багнюці конали,
Слава ж батьку Івану Виговському, слава Україні!
Слава війську козацькому одвіку й до нині!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2339675','Гаї шумлять','Музика: Георгій Майборода Слова: Павло Тичина. Виконує: Лариса Остапенко, Остап Дарчук','uk','ukraine_1991',NULL,NULL,'Джерело: Павло Тичина - Гаї Шумлять: Вокальні твори радянських композиторів, "Музична Україна", Київ',NULL,'Гаї шумлять —
Я слухаю.
Хмарки біжать —
Милуюся.
Милуюся-дивуюся,
Чого душі моїй
Так весело.

Я йду, іду —
Зворушений.
Когось все жду —
Співаючи.
Співаючи-кохаючи
Під тихий шепіт трав
Голублячий.

Щось мріє гай —
Над річкою.
Ген неба край —
Як золото.
Мов золото-поколото,
Горить-тремтить ріка,
Як музика','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2339675'), datetime('now')),datetime('now'));
