INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2339165','В нашім селі на горбочку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'В нашім селі на горбочку
Стоїть церква на видочку,
Коло церкви, ніби квіти,
Сидять старці, ходять діти,
Ходять хлопці і дівчата —
Українські соколята.

А ми, сестри, час не гаймо —
Гаївочки заспіваймо,
Щоби голос наш відбився,
По діброві простелився,
По діброві і по полю,
Де могили є за волю,
По травиці, по шовковій,
Де лежать стрільці січовії.

Вони тоді повмирали,
Як воленьку здобували,
Ви, стрільчики, пісню чуйте,
В темнім гробі не сумуйте.
Ми могили ваші знаємо,
Квіточками уквітчаємо,
Квіточками і вінцями,
І рідними прапорцями.

А ви хлопці тут не стійте,
З дівчатами ся не смійте,
Пригадайте тую славу
Січових стрільців криваву,
І єднайтесь, милі браття,
В одну силу і завзяття,
Щоби наша Україна
Була славна, була вільна!','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2339165'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2339165','В нашім селі на горбочку','В нашім селі на горбочку
Стоїть церква на видочку,
Коло церкви, ніби квіти,
Сидять старці, ходять діти,
Ходять хлопці і дівчата —
Українські соколята.

А ми, сестри, час не гаймо —
Гаївочки заспіваймо,
Щоби голос наш відбився,
По діброві простелився,
По діброві і по полю,
Де могили є за волю,
По травиці, по шовковій,
Де лежать стрільці січовії.

Вони тоді повмирали,
Як воленьку здобували,
Ви, стрільчики, пісню чуйте,
В темнім гробі не сумуйте.
Ми могили ваші знаємо,
Квіточками уквітчаємо,
Квіточками і вінцями,
І рідними прапорцями.

А ви хлопці тут не стійте,
З дівчатами ся не смійте,
Пригадайте тую славу
Січових стрільців криваву,
І єднайтесь, милі браття,
В одну силу і завзяття,
Щоби наша Україна
Була славна, була вільна!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2339767','Ми - брати!','Музика: Павло Зібров Слова: Петро Мага. Виконує: Павло Зібров','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ще як був я колись
Безтурботним хлоп''ям,
Не боявся і не відступав,
В бійку ліз будь яку,
Не тікав у бур''ян,
Задирався і здачі давав!
Все це правда та тільки
Маленьке "але",
Що було надцять років назад,
Був Павлушка - сміливе мале,
Коли поряд ходив старший брат.

Приспів:
Ми - брати, ми - брати,           |
Вчив нас батько як жить-поживать! |
Прут березовий легко              |
В кільце заплести,                |
Але спробуйте віник зламать!      | (2)

Наше щастя у тім,
Щоб не знали біди там,
Де мама у ріднім селі,
Посплітались корінням
Столітні дуби,
Що зросли з однієї землі.
І нічого, що вік вже
Вибілює чуб,
Досі дбаю про брата свого!
Я вам правду скажу, мій девіз:
Зуб за зуб,
Коли брат потребує того!

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2339767'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2339767','Ми - брати!','Ще як був я колись
