INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2339767_l1','pisniua_2339767','YouTube','https://www.youtube.com/watch?v=2Z-jGLKiIjg','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2340665','На Схід!','Музика: Мар''ян Ганусяк Слова: Богдан Ковальчин, Мар''ян Ганусяк. Виконує: Богдан Ковальчин, Віктор Винник','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Застигла кава на вікні, як душа...
Ще крикну - і пошлеш мене зненацька.
Сигарету і чашку кави...
Буває так, що не знаходжу лівих-правих...
Старий наплічник на спині, як тягар,
Що заберу з собою, не залишу спомин.
Затерте фото і лист сльозами -
Все, що залишиться на згадку днів яскравих...

Приспів:
Прощай, кохана!.. Це твоя драма -
Забирай собі і спи сама,
А я поїду на Схід...
Ти спи сама... А я поїду на Схід,
Бо там два моїх кєнта...
А я поїду на схід!.. Не вставай, мала!
А я поїду на Схід зустрічати ранок!..

Гаряче сонце вдалині, як зоря,
Що збереже у темряві сліпої злоби.
По той бік щастя - ти жива,
По цей бік днів -
Один лиш чорно-білий спокій...

Приспів. (2)

Зустрічати ранок...
Зустрічати ранок...','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2340665'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2340665','На Схід!','Застигла кава на вікні, як душа...
Ще крикну - і пошлеш мене зненацька.
Сигарету і чашку кави...
Буває так, що не знаходжу лівих-правих...
Старий наплічник на спині, як тягар,
Що заберу з собою, не залишу спомин.
Затерте фото і лист сльозами -
Все, що залишиться на згадку днів яскравих...

Приспів:
Прощай, кохана!.. Це твоя драма -
Забирай собі і спи сама,
А я поїду на Схід...
Ти спи сама... А я поїду на Схід,
Бо там два моїх кєнта...
А я поїду на схід!.. Не вставай, мала!
А я поїду на Схід зустрічати ранок!..

Гаряче сонце вдалині, як зоря,
Що збереже у темряві сліпої злоби.
По той бік щастя - ти жива,
По цей бік днів -
Один лиш чорно-білий спокій...

Приспів. (2)

Зустрічати ранок...
Зустрічати ранок...');
