INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234111','Ой зза Гори зза Крутої зійшов Місяць ще й з Зорою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пасла Маланка Два Качура Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції. Громадська організація "Арт Екзистенція", Українська експериментальна лабораторія фольклору, Мистецьке агентство "Арт Велес" та Українсько-британське спільне підприємство "Комора" презентують проект "МОЯ УКРАЇНА. БЕРВИ", основна мета якого - показати багатства народної творчості українців. Народна культура та мистецтво українців справедливо вважаються одними з найбагатших надбань культурної скарбниці європейських націй. Проти фольклору боролася церква, його забороняли імперські та радянські укази намагаючись спотворити його сутність банальним псевдофольклором, але фольклор з його глибинною пам''яттю в кілька тисячоліть виявився надзвичайно життєздатним. Схоже на те, що фольклорну традицію може перемогти тільки Час, наступ нової цивілізації. Ми, мабуть, останнє покоління, якому надана можливість зафіксувати кращі зразки традиційної культури, зберегти їх для нащадків, адже живих носіїв автентичного фольклору стає все менше. Протягом ХХ ст. фахівцям-ентузіастам вдалося записати тисячі народних пісень, награвань, творів усної народної творчості, що зберігаються в архівах відповідних державних інституцій. Сьогодні ми ризикуємо втратити цей неоціненний скарб: велика частина унікальних фоноархівів самознищується внаслідок осипання магнітних плівок під дією часу. ("Моя Україна" - автентична музика на СD - http://media.topping.com.ua/printnews/90851.html)','Ой зза Гори зза Крутої
