INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2342073','Не журись, не сумуй!','Музика: Євген Рибчинський Слова: Євген Рибчинський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Не журись, не сумуй! Не сумуй, не журись!
Ти просив у небес проливного дощу.
Дика спека спалила увесь твій врожай,
Ти вважав, що тобі геть усе по плечу...
Тобі небо вказало, де твоя межа.
Ти казав тим, хто плакав: Надійся і вір!,
Але твій довгий шлях зупинила стіна,
Ти благав і молився за спокій і мир,
А наступного дня почалася війна...

Приспів:
Не журись, не сумуй!
Не сумуй, не журись!
Як сказав Соломон: "Все минеться!"
Не журись, не сумуй!
Не сумуй, посміхнись!
Тоді доля тобі посміхнеться...

Ти від відчаю плакав, від болю кричав,
Ти шукав справедливість в поту і крові,
Ти відстоював правду, людей захищав,
Люди подали позов в надії твої...
Ти кохав до нестями, був вірним, як пес,
Вона збігла з коханцем, поки ти спав,
Ти пішов на війну, там помер і воскрес,
Поки ти воював, банк оселю забрав.
Ти просив, аби небо забрало тебе,
Ти хотів самостійно піти в небуття,
Ти з балкону у небо стрибнув голубе,
Та сусід врятував твоє гірке життя...

Приспів.','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2342073'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2342073','Не журись, не сумуй!','Не журись, не сумуй! Не сумуй, не журись!
Ти просив у небес проливного дощу.
Дика спека спалила увесь твій врожай,
Ти вважав, що тобі геть усе по плечу...
Тобі небо вказало, де твоя межа.
Ти казав тим, хто плакав: Надійся і вір!,
Але твій довгий шлях зупинила стіна,
Ти благав і молився за спокій і мир,
А наступного дня почалася війна...

Приспів:
Не журись, не сумуй!
Не сумуй, не журись!
Як сказав Соломон: "Все минеться!"
Не журись, не сумуй!
Не сумуй, посміхнись!
Тоді доля тобі посміхнеться...

Ти від відчаю плакав, від болю кричав,
Ти шукав справедливість в поту і крові,
Ти відстоював правду, людей захищав,
Люди подали позов в надії твої...
Ти кохав до нестями, був вірним, як пес,
Вона збігла з коханцем, поки ти спав,
Ти пішов на війну, там помер і воскрес,
Поки ти воював, банк оселю забрав.
Ти просив, аби небо забрало тебе,
Ти хотів самостійно піти в небуття,
Ти з балкону у небо стрибнув голубе,
Та сусід врятував твоє гірке життя...

Приспів.');
