INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234199','Ходить Ілля на Василя','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Відміна 1: Ходе Ілля на Василя Пасла Маланка Два Качура Роди Боже Жито й Пшеницю. Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції.','Відміна 2:

Ходить Ілля на Василя
Сіє Xугу Життяную
Де сіє там промовляє
Зароди Боже Жито-Пшеницю
І Всяку Пашницю
На Щастя на Здоров''я
На Многая Літа
Щоб у Полі Зерно
А в Xаті Добро!

Відміна 3:

Ходить Ілля на Василя
Носить Пугу Житяную
Де замахне Жито росте
Роди Боже Жито-Пшеницю
Всяку Пашницю
У Полі Ядро а в Домі Добро!

Відміна 4:

Ходить Ілля на Василя
Носить Пугу Житяную
Де замахне Жито росте
Роди Боже Жито-Пшеницю
Всяку Пашницю.
У Полі Ядро
А в Домі Добро!

Відміна 5:

Ходить Ілля на Василя
Куди махне Жито пахне
З Того Колосочка Жита Бочка
Добривечір!

Відміна 6:

Ходить Ілля на Василя
Носить Пугу Житяную
А Другую Просяную
Він сюди махне і туди махне
Усе Житом заросте.
Уроди Боже Жито-Пшеницю
І Всяку Пашницю
У Полі Зерно - а в Домі Добро
На Току Ворошок - а в Печі Пирожок
А мені Пирогів у Мішок!','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_234199'), datetime('now')),datetime('now'));
