INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2346498','Сімейний скарб','Музика: Андрій Ліпінський Слова: Андрій Ліпінський. Виконує: Андрій Ліпінський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ці слова я скажу тобі,
Що ти - скарб у моєму житті,
Ти дана мені з висоти небес,
Ми - сім''я тепер
І в нас син росте!

Приспів:
Я вдячний Богу за все, що є!
Іде рік за роком - і син росте!
Пройдуть роки й наступить час
І син піде в життя шукати скарб!
Дарую я тобі букет троянд,
Ціную я в тобі - це твій талант:
Кохати вірно так вмієш ти,
Усмішки щирої більш не знайти!

Ти є сяйво, що сліпить в ночі,
Ти є муза й натхнення мені,
Ти є квітка, що цвіте завжди,
Мені - жінка, мати - синові!

Приспів.

Пригорну тебе до свого плеча,
Затремтить в душі,
Виступить сльоза
Це вони - ці сльози радості,
Які ллються з глибини душі!

Приспів.','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2346498'), datetime('now')),datetime('now'));
