INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2345675','Свято Миколая','Музика: Віталій Лазаренко Слова: Раїса Обшарська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дожидаються дорослі,
Діточки чекають
Того дня, коли настане
Свято Миколая.
Як прийде святий угодник
До нашої хати,
То у дзвоники задзвонять
Божі янголята.

Завітає і в багату,
І в бідну родину,
Не обмине, не покине
Найменшу хатину:
І цукерки та іграшки,
І бубликів в''язку
Подарує чемним дітям,
Ще й добро та ласку.

Тихесенько під подушку
Дари поскладає,
І чарівна добра казка
В танці закружляє.
І над цілою землею
Зорі засіяють,
Бо святого Миколая
Увесь рік чекають...','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2345675'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2345675','Свято Миколая','Дожидаються дорослі,
Діточки чекають
Того дня, коли настане
Свято Миколая.
Як прийде святий угодник
До нашої хати,
То у дзвоники задзвонять
Божі янголята.

Завітає і в багату,
І в бідну родину,
Не обмине, не покине
Найменшу хатину:
І цукерки та іграшки,
І бубликів в''язку
Подарує чемним дітям,
Ще й добро та ласку.

Тихесенько під подушку
Дари поскладає,
І чарівна добра казка
В танці закружляє.
І над цілою землею
Зорі засіяють,
Бо святого Миколая
Увесь рік чекають...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2341192','Червона калино.','Слова: Володимир Дашавський','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Калино, червона калино,
Який гарний твій білий цвіт,
Дівчино, моя люба дівчино,
Не милий мені без тебе світ.

Калино, кучерява калино,
Гарні червоні грона твої.
Дівчино,молодая дівчино,
Чому без тебе сумні мої  дні.

Калино, пишна калино,
Ягоди соком ти  наливаєш,
Скажи мені лісовая красуне,
Чи когось щиро кохаєш?.

Кохаєш його дуже щиро,
Ягідки для нього тримаєш
Посміхаєшся  йому мило,
І листочками його обнімаєш.

Калинонька  посміхнулась,
До дуба листком доторкнулась,
Тільки тебе я, дубочку, кохаю,
І ягідки спілі тобі тримаю...','["pisni.org.ua", "cat:boykivski", "Пісні з Бойківщини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2341192'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2341192','Червона калино.','Калино, червона калино,
Який гарний твій білий цвіт,
Дівчино, моя люба дівчино,
Не милий мені без тебе світ.

Калино, кучерява калино,
Гарні червоні грона твої.
Дівчино,молодая дівчино,
Чому без тебе сумні мої  дні.

Калино, пишна калино,
Ягоди соком ти  наливаєш,
Скажи мені лісовая красуне,
Чи когось щиро кохаєш?.

Кохаєш його дуже щиро,
Ягідки для нього тримаєш
Посміхаєшся  йому мило,
І листочками його обнімаєш.

Калинонька  посміхнулась,
До дуба листком доторкнулась,
Тільки тебе я, дубочку, кохаю,
І ягідки спілі тобі тримаю...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2346573','Танцювала карапет','Українська народна пісня. Виконує: Інна Книжник','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Танцювала карапет,
Порвала ботінки,
Осталися на ногах
Чулки да резінки,
А музики грають,        |
Аж чулки спадають,      |
А підошви з ботінок     |
Собаки таскають!        | (2)

Якби мені зранку
Горілочки чарку,
Не діда старого,
Хлопця молодого!
Я би з ним гуляла,      |
Всю нічку не спала,     |
Бо я жінка не свята,    |
В мене правдонька своя! | (2)

А дєвочка Рая
Упала з сарая,
Який тебе чорт послав,
Моя дорогая?..
Упала з сарая,          |
Порвала спідницю,       |
Ще й до смерті налякала |
Молоду телицю!          | (2)

Ресторан відкрили,
"Старт" його назвали,
Поруч витверезник,
"Фінішом" назвали.
Ой, не пийте, хлопці,   |
Міцної горілки,         |
Бо буде вам карапет     |
Від рідної жінки!       | (2)

Танцювала карапет,
Порвала ботінки,
Осталися на ногах
Чулки да резінки,
Ви, музики, грайте,     |
А ви, люди, чуйте,      |
В кого ноги не болять - |
Карапет танцюйте!       | (2)','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2346573'), datetime('now')),datetime('now'));
