Ще й в Дзвони дзвонять');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234277','Свята ніч','Музика: Franz X. Gruber Слова: Fr. Joseph Mohr. Виконує: Руслана, Тарас Чубай','uk','ukraine_before_1917',NULL,NULL,NULL,'Підбір акордів: Роман Бучко','Свята ніч, тиха ніч,
C(III)      F
Ясність б''є від зірниць
Дитинонька пресвята
Така ясна, мов зоря,

Спрочиває тихо
Тихо, в тихім сні

Тиха ніч, свята ніч,
Гей, утри сльози з віч!
Бо син Божий йде до нас
Цілий світ любов''ю спас

Витай нам Святе дитя!
Витай нам Святе дитя!

Свята ніч настає,
Ясний блиск з неба б''є,
В людськім тілі Божий Син
Прийшов нині в Вифлеєм,

Прийшов щоб спасти
Цілий світ.','["pisni.org.ua", "cat:christian", "cat:kolyadky", "Пісні на християнську тематику", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_234277'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_234277','Свята ніч','Свята ніч, тиха ніч,
C(III)      F
