INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_234277_l1','pisniua_234277','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23461','Бог предвічний народився','(Бог предвічний). Українська народна пісня. Виконує: Глорія, Боян, Дударик','uk','ukraine_before_1917',NULL,NULL,'народна коляда','У книзі "Колядки" (Колядки.- Львів: Каменяр, 1990.- 64 с.) тут є інші варіанти тексту: * З желанєм, спокоєм. ** І Пану нашому. *** Більшість сучасних джерел подає "І утішився", проте автентичний і більш логічний варіант звучить власне так, як подано тут. Старовинні співаники теж містять такий рядок У кожному куплеті 2 останні рядки співаються двічі.','Бог предвічний народився,
Прийшов днесь із небес,
Щоб спасти люд свій весь,
І утішив вся ***.

В Вифлеємі народився,
Месія, Христос наш,
І пан наш, для всіх нас,
Нам народився.

Ознаймив це Ангел Божий
Наперед пастирям,
А потім звіздарям
І земним звірям.

Діва Сина як породила,
Звізда ста, де Христа
Невіста Пречиста
Сина зродила.

Тріє царі несуть дари
До Вифлеєм-міста,
Де Діва Пречиста
Сина повила.

Звізда їм ся об''явила,
В дорозі о Бозі,
При волі, при ослі
Їм ознаймила.

"Тріє царі, де ідете?"
"Ми ідем в Вифлеєм,
Вінчуєм спокоєм  *
І повернемся".

Іншим путем повернули,
Погану, безстидну,
Безбожну Іроду
Не повідали.

Йосифові Ангел мовить:
З Дитятком і з Матков,
З бидлятком, ослятком
Хай ся хорониить.

"Слава Богу!" - заспіваймо,
Честь Сину Божому
Господеви нашому - **
Поклін віддаймо','["pisni.org.ua", "cat:christian", "cat:kolyadky", "cat:narodni", "Пісні на християнську тематику", "Колядки", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23461'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23461','Бог предвічний народився','Бог предвічний народився,
Прийшов днесь із небес,
