INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2349717','З днем народження',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ми вітаєм тебе,
