INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_234859','Гора, гора, гей','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Самвидавний туристський пісенник "Там на Лемковині помедже горами". - Літо, 1981.',NULL,'Гора, гора, гей, и долина,
Не буду я, гей, материна.

Приспів:
Лем собі за горку зайду,
Там собі фраїра найду,
Лем собі за горку зайду,
Там собі фраїра найду.

Лем я буду, гей, Ваничкова,
Бо Ваничко, гей, душа моя!

Приспів.

Гора, гора, гей, верх сосновий,
Не вір, дівча, гей, фраїрови...

Приспів.

Вітер дує, гей, вершок зламе,
А паробок, гей, дівча, скламе.

Приспів.

Вітер дує, гей, верхы клонит,
За Ваничком, гей, серце болит...','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_234859'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_234859','Гора, гора, гей','Гора, гора, гей, и долина,
Не буду я, гей, материна.

Приспів:
Лем собі за горку зайду,
Там собі фраїра найду,
Лем собі за горку зайду,
Там собі фраїра найду.

Лем я буду, гей, Ваничкова,
Бо Ваничко, гей, душа моя!

Приспів.

Гора, гора, гей, верх сосновий,
Не вір, дівча, гей, фраїрови...

Приспів.

Вітер дує, гей, вершок зламе,
А паробок, гей, дівча, скламе.

Приспів.

Вітер дує, гей, верхы клонит,
За Ваничком, гей, серце болит...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2347471','Сталеві квіти','Музика: Андрій Хливнюк, Павло Литвиненко Слова: Андрій Хливнюк. Виконує: Бумбокс','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Кажеш - все про мене знаєш ти,
Навіть, стіни мають очі тут.
Ну у кого вже навчилася? -
Дай йому мою сорочку, білу ту.
Ти така, як я, незламана,
Troubles saіd "hello",
Joy saіd "peace and love",
Але там, де я себе запхав
Ані психолога, ні шамана...
Після всього через що пройшли
Починати знову все з нуля?..
Небо-небо, чуєш, небо, я земля,
Бо вже той день, коли
Ми зриваємося на крик
І я не знаю, тепер звик,
Якщо можеш без мене далі йти,
То підкажи, коли відпустить...
В руки твої, що очікують,
Крізь валуни човен правлю,
Зі шкіри вистрибну списом,
Стрілою наввиперед.
Поряд в останній твій зойк
Я себе поставлю,
Аби все знов розпочати,
Зіграти наш спільний сет!

Приспів:
Посеред стиглої ночі                 |
Транслюють солодкі сни нам,          |
А ми дивитись не хтіли,              |
Як квіти сталеві ростуть із глини... |
Ми сподівались від бруду вимитись,   |
За руки взятись і вийти!..           |
Вибач, я більше не буду з бруду      |
Ростити сталеві квіти!..             | (2)

Так усе й влаштовано:
Тут зашив - там тече...
Якщо впав - встань знов,
Переклав на інше плече - пішов!
Брак людей, сутінки думок,
Поклади їм край!
Коли все ніяк - перевертай вініл,
Крути ще!
Куплені-продані, забуті-згадані,
Але не крадені
Сонячні наші дні - Ні!
Різні, коли брудні,
Коли тендітні - Ні!
Хочеш пробач, хочеш "ізвіні" -
Але ким тобі був? Ким тепер став?
Ким була мені?
Ми були на все це згодні!
Прошу, тільки не сьогодні...
Чуєш?.. Тільки не сьогодні...
Я намагався, навіть, на горі
Бути ким я є...
Лиш мені моє, собі лиш своє,
Бо невдовзі хвилі змиють сліди там,
Де спільну мову шукав з тобою.
В небі нічному серпневому
Наше придане.
Чому так довго минав,
Хто ховав, де ховалися?..
Вип''ю тебе по краплині -
І все дізнаюся:
Скільки на двох нам жетонів
В цій касі видано...

Приспів.

Але ось тут, прямо тут,
Між ребер з''явився порожній кут...
Я кричав, просив, благав: вважай
Бо ти для мене і пекло, і новий рай
Схибили раз - і все нанівець.
Так мій зошит зламав її олівець.
Так, я сильний, я вільний, але пустий.
Ти підкажи, коли відпустить?..

Приспів.','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2347471'), datetime('now')),datetime('now'));
