INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235114','Ой Сивая та і Зозулечка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Колядка стародавня: Українське Різдво Світа. Йа всі Луги облітала. Рай розвився Господь звеселився. Радуйся Земле Коляда іде! Сивесенька Зазуленька. Ця Колядка цілком подібна до Колядок про Астральну Трійцю в Новій Світлиці серед Праморя. Бо оця Астральна Трійця, хоч є символом Первовічних і завсігди в природі чинних сил, то є заразом символом Первісних часів, Первовічного життя і Первісних людей. Тому є в Колядках часто такі образці про Астральну Трійцю: Сивесенька Зазуленька Йа всі Луги облітала А в Одному не бувала А в тім Лузі Три Церковці А в тій Церкві Три Віконці А в Одному Ясний Місяць А в Другому Ясне Сонце А в Третому Ясні Зірки То не Місяць сам Господар То не Сонце Господиня То не Зірки то їх Дітки! Цей "Оден Луг" — то Первісний луг; потрійна церковця — це та сама Нова Світлонька Первовічна: Небо, де мешкають Три Святці: Сонце, Місяць і Ясна Зоря, про яких співає багато Колядок, а все разом у Первовічній добі, якої був свідком і в ній брав живу участь — таємний Виз. Реліґійна служба Богу. Коляда виражує дійовий культ і вселюдний реліґійний настрій народу, народний душевний зов до реліґійної служби Богу. Може і тому є в Українського народу в великій пошані установа Колядників, ревних служивців старого шанування. Вже Передріздвяний час виявляв, що зближається дуже святочна хвиля, глибоко прочута народом, наперед опановуюча його всю психіку й всі почування. Це — Святий Вечер, властиве свято Різдва-Коляди, що містить у собі всю суть того Свята. Це велике громадянське й культурне Українське свято — вислів найстарших народних традицій і атавістичних почувань та день духової, культурно-реліґійної, всенародної обнови. Обряди слідуючих днів, хоч нарід лучить їх формально з Різдвом Христовим, належать у суті річи до Староукраїнського Святого Вечера і показують його ідеольоґію. Старовіцькі Колядки і Щедрівки, своїм змістом так дуже не підхожі до церковно-християнської ідеольоґії Різдва, узгоджуються натомість на причуд з Українським Святим Вечером і поширюють якраз його провідні ідеї. Їх колядує та щедрує нарід не тільки зараз після Святого Вечера, але і опісля, через цілі Свята різдвяні та Щедрий Вечер, ба, і далі — аж до Стрітення Господнього (27-го дня після Щедрого Вечера) і що цікаве: через цілий світлий час Місячний! Українські мотиви Свята виходять передовсім з почувань реліґійних, основаних на найдавніших традиціях, мабуть старших, ніж традиції племінні, — мова ж бо про перші реліґійні почування людства. Яке інше значення може мати на Святий Вечер лагодження "усякого хліба, що Бог уродив", його жертвоприношення й святочне споживання, — як не радісний вислів з його посідання, й почуття вдяки для Того, від кого той хліб походить. Господарі порядкують на обійстю, вичищують стайні, — а що особливо звертає увагу, миють та чешуть худобу, стараються, щоб вона була вся на Свят-Вечір у загороді та брала участь у Святі і в Тайній Вечері. Це відзиваються в душі народу його колишні первісні почування для худоби, коли він перший раз її придбав і мав утіху з її сотворення. Оце пам''ятання про домашню худобу і віддання їй першенства в поживанні Святої Вечері характеризує велике благородство душевне Українського простого народу, який видить у худібці твар Божу та своїх помічників і приятелів. Воно вказує, як не забуває нарід старинної традиції про це, що Різдвяний вечер є також Святом худоби й її Сотворення. З цього огляду має угощення й благословення худоби вид окремої культурно-реліґійної дії. (За працею: о. Ксенофонт Сосенко. "Культурно-історична постать Староукраїнськиx свят Різдва і Щедрого Вечора". Львів, 1928. - СІНТО, Київ 1994. 343с.) Читати листки з приводу цієї Пісні: Бог, Різдво Світа, Дідух і Лицарі. Колядки як Українські релігійні роздуми про Бога. Стежки до інших листків про Українські традиції.','Ой Сивая та і Зозулечка

