INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235096','Ой у Полі при Дорозі Щедрий Вечір','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Буде Тобі Три Дорозі. Буду в січі жить Бога боронить. Ой у Полі Полі Василечко оре. Гей понад Лужок оре там Плужок Ой у Полі Полі Василечко оре Ой чий же то Плужок так рано вийшов Під Дубиною під Зеленою Розійдися Туманочку оре Милий із Раночку Сіно косить Коню носить. Ой у Полі при Дорозі Щедрий Вечір Коника пасе на Скрипці грає. Там за Дунаєм Музиченьки грають Коня напуває личко умиває. Там на Річці на й Ордані Івана Купала тай в Воду упала. Ой біжит Коник під Гречкою Поскакав Коник попід Гречкою Хтось у Борі гукає Ой Пане-пане пригадай собі. Ой Коню Коню я Тебе продам Любило мене аж Три Дівочки. Ой під Вербою під Зеленою Святий Вечір Виведи Коника Дівчино Панна. Сволока тече в Хаті Болото Грай Кониченьку Сивий Маленький зо мною. Там за Горею за Високею Возьмуть Коня ще й Сідельце. Смутний Вечір Смутний Ранок Як Сурми заграють Спутай Коня на Отаву в залізнії пути. В Чистому Полі Сам Плужок ходить. А всі Святії за Погоничів за Посівачів. Символіка Щедрого Вечера і Василя. Щедрий Вечер зачинається властиво під Новий Рік, 13-14 січня (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Щедрий Вечер, 13-14 січня. Маланки-Василь. Коза. Щедрий Вечер, 18-19 січня: Святі Водорщі. Стежки до листків про Українські традиції.','Ой у Полі при Дорозі

Приспів:
