INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2351055','Снігова пісенька "Лети, сніжок"','Музика: Микола Шуть Слова: Микола Шуть','uk','ukraine_1991',NULL,NULL,'http://artteacher.ucoz.ru/load/fonogrami_ta_pisni_shkilnikh_svjat/novij_rik/leti_leti_s nizhok_komple',NULL,'Весело кружляє сніг, сніг,
Віхолою грає сніг, сніг,
Стеле без зупину сніг, сніг,
Снігову перину сніг...

Приспів:
Лети, лети, сніжок,
Легкий, мов пушок,
Лети, лети, сніжок,
