INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2351515','Дід Мороз пішов у ліс','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.minus.lviv.ua/minus/artist/%D0%9D%D0%B5%D0%B2%D1%96%D0%B 4%D0%BE%D0%BC%D0%B8%D0%B9%20%D0%B',NULL,'Дід Мороз пішов у ліс,
Тихий ліс, білий ліс.
Він ялинку нам приніс,
Пишну й зелененьку.
Ми прикрасили її
У вогні чарівні.
В коло стали й заспівали
Пісню веселеньку!

Приспів:
Кульки на ялиночці -
Зірочки, зірочки,
Дружать із ялинкою
Малюки, малюки,
Всім на святі хочеться
Заспівать, заспівать,
Ніжки в лад із піснею
Дріботять, дріботять...

Із Морозом-дідусем
Хоровод поведем,
Гарно свято проведемо
З танцями й піснями.
Хай зима потішить нас
Білим снігом раз у раз,
Хай у цей святковий час
Всі танцюють з нами!

Приспів. (2)','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2351515'), datetime('now')),datetime('now'));
