INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2352665','Летіла лелека','Музика: Майя Янчишин-Чедрик Слова: Майя Янчишин-Чедрик. Виконує: Дует MOVA','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Летіла лелека
Онде, не далеко,
Крихітне малятко
Принесла у хатку...
Наче намистиночка,
Малесенька дитиночка,
Люлі-люлі, баю, |
Тебе колихаю... | (2)

Соловей щебече,
Вже надходить вечір,
Вітер у гаю шумить -
Колискову гомонить...
Сплять уже звірятонька,
Сірі зайченятонька...
Люлі-люлі, баю, |
