INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2349797','Маленький трамвайчик','Музика: Олександр Шевченко Слова: Олександр Шевченко','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','Пісню виконує Віра Кідик.','Маленький трамвайчик
У місті маленькім
Із раннього ранку
Невтомно кружля,
Старанний трамвайчик,
Трудяга маленький,
Він возить, і возить,
І возить малят.

Приспів:
Трамвайчик маленький
По місту кружля!
Маленький трамвайчик,
Що возить малят!

Рушаємо разом,
Сідай сміливіше,
Дзвенить наш трамвайчик
На вулицю всю,
Щоб їхати швидше
І ще веселіше,
Співаємо разом
Ми пісеньку цю.

Простує трамвайчик
По рейках маленьких,
Маленьке усе
За віконцем малим,
Маленькі будинки,
Ми їдемо містом
Маленьким таким.

Приспів.

Закінчиться день,
Тоді вечір настане,
Трамвайчик стомився,
Давай, спочивай,
Ми виростем скоро,
Дитинство скінчиться,
І виросте з нами
Маленький трамвай.

Приспів.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2349797'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2349797','Маленький трамвайчик','Маленький трамвайчик
