INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23522','Дивная новина','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'народна коляда',NULL,'Дивная новина: Нині Діва Сина
Породила в Вифлеємі, Марія єдина!         | (2)

Не в царській палаті, а межи бидляти,
У пустині, у яскині, треба то всім знати. | (2)

Що то Бога іста Марія Пречиста
І рождає, і питає Його як невіста.        | (2)

На руках тримає, пісеньки співає,
Всемогучим Створителем Його називає.      | (2)

Мовить: "Люляй, Сину, Я тебе повину,
Бо Ти собі вибрав мене за матір єдину!"   | (2)

"О, необійменний, о, непостиженний,
Спи ти довго, рости скоро, младенче блаженний!" | (2)

"Я в тобі надію, Сину мій, лелію:
Де сам будеш, мене візьмеш, Ти мій Добродію". | (2)

"Скажи, Правосуде, де хто з вірних буде?
Хай зі мною пред Тобою стануть усі люди"  | (2)

"Щоб Тебе молити і Тебе просити,
Щоб Ти дав нам в своїм Царстві            |
Во вік віків жити"                        | (2)','["pisni.org.ua", "cat:christian", "cat:kolyadky", "cat:narodni", "cat:zakarpatski", "Пісні на християнську тематику", "Колядки", "Народні пісні", "Закарпатські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23522'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_23522','Дивная новина','Дивная новина: Нині Діва Сина
Породила в Вифлеємі, Марія єдина!         | (2)

Не в царській палаті, а межи бидляти,
