INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_23515','Вселенная, веселися!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'народна коляда',NULL,'Вселенная, веселися!
Бог від Діви днесь родився.
У вертепі між бидляти,
Там поклін Христові дати
Царіє, царіє приходять.     | (2)

Ладан, миро, золоти в дари
Там принесли тріє царі
Народженому Цареві,
Всього світу Господеві,
Віддали, віддали в покорі.  | (2)

Пастиріє прибігають,
На сопілках вигравають.
Бо пізнали що Рожденний,
Із Марії воплощенний,
Чистої, чистої Дівиці.      | (2)

Ти, Йосифе, не смутися,
Це Спаситель народися!
Радість Він Тобі приносить,
Нам спасення всім голосить
Від нині, від нині навіки.  | (2)

Там Ангели припадають,
"Слава во вишніх" співають,
Рожденому Отрочаті
Поспішаються честь віддати:
Богові, Богові у яслах.     | (2)

Пастирям уподобімся,
Рожденому поклонімся,
Щоб дозволив мирно жити,
Смуток в радість замінити -
Віруючим, віруючим у Нього. | (2)    За Іваном Біликовським','["pisni.org.ua", "cat:kolyadky", "cat:zakarpatski", "Колядки", "Закарпатські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_23515'), datetime('now')),datetime('now'));
