INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2353158','Секрет','Музика: Друга ріка Слова: Валерій Харчишин. Виконує: Друга ріка','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Люди, як люди,
А я народився старим,
Хоч був колись добрим малим...
Так, старим малим...
Літав і не загинув, але,
Мабуть, на небі таки місця нема,
Чи черга моя не дійшла,
І замість мене там ви, а не я...
Летять картини,
Я колись піду та ти не будеш один,
Запам''ятаюсь тобі таким -
Веселим, трохи сумним...
Посміхайся, син!

Приспів:
Я нікому не скажу!..
Я не видам наш секрет...
Не забирай, кого люблю -
Забери мене...
Я нікому не скажу!..
Я не видам наш секрет...
Не забирай, кого люблю -
Бери мене... Бери мене...

О, Боже, знаєш,
Для чого ти їх забираєш,
І нас сумних залишаєш?..
Хіба ж їм тут місця нема?..
Скажи, в чому я винний?..
Боже, знаєш,
Для чого їх від мене ховаєш?..
Десь у хмарах, ну, як вони там?..
Скажи, хоч як вони там?!?

Приспів.

Я нікому не скажу!..
Я не видам наш секрет...
Не забирай, кого люблю -
Забери мене... Бери мене!..','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2353158'), datetime('now')),datetime('now'));
