INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2355550','Лічить кроки старенький годинник','Музика: Віктор Ох Слова: Віталій Назарук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Лічить кроки старенький годинник,
До Різдва кілька срібних сніжин,
Із минулого запах цитринний
Гладить хутро красуньок ялин...

Стіл святковий змахне рушниками -
І, як диво, запахне кутя,
Примовляючи: Зірка над нами -
Тож родилося Боже Дитя!

Десь надворі лунають колядки,
Ходять Сонце із Місяцем вдвох -
Носять кожній родині на свято
Промінцями Любов і Добро!

Стіл святковий гостей пригощає,
І по колу кружляє кутя.
А згори Зірка всім сповіщає:
Народилося Боже Дитя!

Оживають портрети на стінах,
Зупиняється в просторі час.
Це вона - наша ненька Вкраїна -
У родину об''єднує нас!

За святковим столом пригадаймо
Тих, що наше боронять життя,
Долі їм у Зорі попрохаймо,
Що явила нам Боже Дитя!','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2355550'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2355550','Лічить кроки старенький годинник','Лічить кроки старенький годинник,
