INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2354653','Струмочок','Музика: Олександр Кварта Слова: Роман Кахович. Виконує: Олександр Кварта','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В небі горять стожари,
Час молодим любити!
Ти — мій струмок бажаний,
Коли я хочу пити!
Ти все біжиш невпинно,
Маєш джерельну силу,
З гір у саму долину -
Наче у тебе крила!

Приспів:
Біжи, біжи, струмочку, |
Стрімко ставай рікою!  |
Вийду я до місточку    |
Та й стрінуся з тобою! | (2)

Там у долині квіти
Переплели покоси,
Сонця малії діти
Пити благанно просять.
Десь вітерець в садочку
Тішить зелені віти,
Як же в тобі, струмочку,
Ноги не замочити?..

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2354653'), datetime('now')),datetime('now'));
