INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2354653_l2','pisniua_2354653','YouTube','https://www.youtube.com/watch?v=vV3W6hgBQ0M','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2354354','Сто відсотків щастя','(Матуся сорочку мені вишивала). Музика: Олексій Малахов Слова: Олексій Малахов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Матуся сорочку мені вишивала
І тихо співала пісні
Про вічне кохання,
Про мить сподівання,
Та зичила щастя мені.
Вона вчила мене дарувати добро,
Я бажаю його вам усім!
Хай минає печаль і розвіється зло,
Хай лелеки летять в кожен дім!

Приспів:
Сто відсотків щастя бажаю вам!
Сто листів кохання і телеграм!
Друзів на всі віки і шлях легкий,
Щоб серця палали живим вогнем!
Мрії хай збуваються день за днем!
Миру у кожен дім бажаю всім! Всім!

Матуся сорочку мені вишивала,
Немов малювала весну,
Її одягла - і крилатою стала,
Вночі я тепер не засну.
Полечу я до вас через ріки, поля,
По країні добро понесу!
Хай в любові живе українська земля,
Побажання в піснях донесу!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "cat:pro-ditey", "Пісні про любов до батьків", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2354354'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2354354','Сто відсотків щастя','Матуся сорочку мені вишивала
