INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2355859','Україна-Мати!','Музика: Олександр Морозов Слова: Борис Олійник. Виконує: Віталій Білоножко, Віталій Білоножко (молодший)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Чорний вітер, жовтий смерч...
Так у вічній коловерті:
При дорозі бродить смерть,
Та нема дорозі смерті...
Всі колись довершим круг
На вінкові, на печалі...
Та повів безсмерттям рух |
Нескінченної спіралі...  | (2)

Коні круто крешуть в брук:
Ще копита не притерті.
Доки є дорога й рух,
Доти, брате, ми безсмертні!
Тож, на коней! Зло до пня
Підкоси мечами правди!
Хай нагірно осіння        |
Хустка матері, як прапор! | (2)

Рід наш - з кореня верби,
Не шукай древніше знаті:
На фамільному гербі
Ми карбуєм вічне: "Мати!"
В чорнім горі і журі
Віру нашу не підтяти:
Умирають матері,          |
Та не вмре ніколи Мати!   | (2)

В чорнім горі і журі
Віру нашу не підтяти:
Умирають матері,          |
Та не вмре ніколи Мати!   | (2)','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2355859'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2355859','Україна-Мати!','Чорний вітер, жовтий смерч...
