INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_2355859_l1','pisniua_2355859','YouTube','https://www.youtube.com/watch?v=sgDjeLJJrNw','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2356756','Україна, ти - моя родина!','Музика: Катя Бойко Слова: Катя Бойко. Виконує: Катя Бойко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На світанку вийду я у чисте поле,
Привітаю з новим днем усе навколо!
І у відповідь озветься вітер мудрий,
Захитає колоски, дерева збудить!
Тепле сонечко за плечі обіймає
І пташки свої пісні мені співають!
Усміхаюсь і радію я життю,
Батьківщину свою щиро я люблю!

Приспів:
Україна, ти - моя родина!      |
Ти - моя єдина, матінка земля! |
Пісня серця мого лине,         |
Сяють очі сині, радіє душа!    | (2)

Завітаю я до дому на свята -
Зустрічає дружньо вся моя рідня.
Це мій рідний край, це моя земля,
Я - щаслива українка молода!
Тепле сонечко за плечі обіймає
І пташки свої пісні мені співають!
Усміхаюсь і радію я життю,
Батьківщину свою щиро я люблю!

Приспів.','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2356756'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2356756','Україна, ти - моя родина!','На світанку вийду я у чисте поле,
