INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_235716','На покинутих згарищах','Українська народна пісня. Виконує: Рутенія, Андрій Безуглий','uk','ukraine_before_1917',NULL,NULL,'Демо-альбом "Рутенія. Безіменні" (2003)','Текст і акорди взято з аудіо-джерела. Акорди підібрано на слух. Тональність оригінальна. Підбір акордів: bohdanko (pisni.org.ua)','На покинутих згарищах   сумно віють вітри,
Де вони розпрощалися... Він сказав: "Мушу йти..."
І дівчину заплакану   кинув він молоду,
І сказав їй: "Зі славою   я до тебе прийду."
Приспів:
Он   там ліси гудуть... Там вояки їдуть.  |
Он   в лісовий туман йдуть відділи УПА.   | (2)
Dm               F      Gm              A ...
Із друзями подібними   його доля звела.
І пішов він до рідно до своєї УПА.
І поглянув востаннєє милий в теє вікно,
Де сиділа коханая, цілувала його.
Он там ліси гудуть... Там вояки їдуть.    |
Он в сніговий туман йдуть відділи УПА.    | (2)
Друзі з радістю стрінули молодого стрільця,
Розказали про подвиги, про повстанське життя.
І поглянув востаннєє милий в теє вікно,
Де сиділа коханая, цілувала його.
Он там ліси гудуть... Там вояки їдуть.    |
Он в сніговий туман йдуть відділи УПА.    | (2)','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_235716'), datetime('now')),datetime('now'));
