INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2356410','Келих дружби','Музика: Павло Мрежук. Виконує: Павло Мрежук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дні, як птиці віщі, вийдуть непомітно,
На вершини літа доля доліта.
Нам у колі друзів затишно й привітно,
Хоч на мить спиніться, молоді літа!

Приспів:
Багряним листом кружляє осінь,
У серці завжди в нас весна!
Ми келих дружби дзвінкий підносим,
За нашу дружбу п''ємо до дна!

В зоряному краю, де студені роси,
Хліб і сіль ділили, клали борозну,
Пам''ятаєш, друже, золоті покоси
Там, де ми топтали стежку не одну?..

Приспів.

Нас з тобою, друже, не зігнуть вітрами,
Хоч і вже сріблиться перша сивина...
Вип''ємо за друзів, тих, хто поруч з нами!
Вип''єм і згадаєм тих, кого нема...

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2356410'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_2356410','Келих дружби','Дні, як птиці віщі, вийдуть непомітно,
На вершини літа доля доліта.
Нам у колі друзів затишно й привітно,
Хоч на мить спиніться, молоді літа!

Приспів:
Багряним листом кружляє осінь,
У серці завжди в нас весна!
Ми келих дружби дзвінкий підносим,
За нашу дружбу п''ємо до дна!

В зоряному краю, де студені роси,
Хліб і сіль ділили, клали борозну,
Пам''ятаєш, друже, золоті покоси
Там, де ми топтали стежку не одну?..

Приспів.

Нас з тобою, друже, не зігнуть вітрами,
