INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_2356158','У ніч Святого Миколая','Слова: Іванна Савицька','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує дитячий фольклорний ансамбль Яворина.','Темна нічка за шибками,
Сон на крилах вже летить.
Небеса блищать зірками,
Та Івасик ще не спить...

У голівці сонній мрії:
Хмари, небо, зорі, рай,
Білі Ангели-лелії,
А між ними Миколай...

На санчатах щедрі дари —
Вже готове все як слід.
Ангели стають у пари
І злітають вниз, на світ...

Миколай — дідусь старенький —
Ставить дари на столі,
А Івась питає неньки:
Ненечко, чи це мені?

Темна нічка за шибками
Заглядає до вікон,
Спить Івасик біля мами,
Усміхаючись крізь сон...','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_2356158'), datetime('now')),datetime('now'));
